                    className={`flex items-center justify-between p-3 rounded-lg cursor-pointer transition-colors text-sm ${activeSessionId === session.id ? 'bg-gray-100 dark:bg-gray-800 text-gray-900 dark:text-white font-medium border-l-4 border-primary-500 shadow-sm' : 'text-gray-600 dark:text-gray-400 border-l-4 border-transparent hover:bg-gray-50 dark:hover:bg-gray-800/50'}`}
                    role="menuitem"
                    aria-label={`${t('action.select_chat_session', language)}: ${session.title || t('msg.new_chat_title', language)}`}
                >
                <span className="truncate flex-1">{session.title || t('msg.new_chat_title', language)}</span>
                <button onClick={(e) => onDeleteSession(e, session.id)} className="p-2 text-gray-400 hover:text-red-500 transition-colors" aria-label={`${t('action.delete_chat_session', language)}: ${session.title || t('msg.new_chat_title', language)}`}><Trash2 className="w-4 h-4" /></button>
                </div>
            ))}
            </div>
          </div>

          <div className="mt-4 pt-4 border-t border-gray-200 dark:border-gray-800 space-y-3">
             <button 
                onClick={() => { onOpenSettings(); onClose(); }} 
                className="btn-secondary w-full justify-start"
                aria-label={t('action.open_settings', language)}
             >
               <Settings className="w-5 h-5" />{t('action.settings', language)}
             </button>
          </div>
      </div>
    </div>
  );
};

export default MobileMenu;

"use client";

import React, { useState, useRef, useEffect } from 'react';
import { ChevronDown, Check, Bot } from 'lucide-react';

interface ModelSelectProps {
  value: string;
  onChange: (value: string) => void;
  options: string[];
  placeholder?: string;
  disabled?: boolean;
  className?: string;
  emptyMessage?: string;
  onOpenChange?: (isOpen: boolean) => void;
}

export const ModelSelect: React.FC<ModelSelectProps> = ({
  value,
  onChange,
  options,
  placeholder,
  disabled,
  className,
  emptyMessage = "No models available",
  onOpenChange
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    onOpenChange?.(isOpen);
  }, [isOpen, onOpenChange]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSelect = (option: string) => {
    onChange(option);
    setIsOpen(false);
  };

  return (
    <div className={className || "relative flex-1"} ref={wrapperRef}>
      <div className="relative flex items-center">
        <input
          type="text"
          className="w-full bg-transparent text-xs outline-none font-medium text-gray-700 dark:text-gray-200 min-w-0 py-0.5"
          placeholder={placeholder}
          value={value}
          onChange={(e) => {
            onChange(e.target.value);
            setIsOpen(true);
          }}
          onFocus={() => setIsOpen(true)}
          disabled={disabled}
        />
        <button
          onClick={() => !disabled && setIsOpen(!isOpen)}
          className="ml-1 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 transition-colors focus:outline-none"
          disabled={disabled}
          tabIndex={-1}
        >
          <ChevronDown className={`w-3.5 h-3.5 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`} />
        </button>
      </div>

      {isOpen && (
        <div className="absolute bottom-full mb-1 left-0 right-0 max-h-56 scrollbar-overlay bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg shadow-xl z-50 animate-fade-in-up">
            {options.length > 0 ? (
                <div className="py-1">
                    {options.map((option) => (
                        <button
                            key={option}
                            onClick={() => handleSelect(option)}
                            className="w-full text-left px-3 py-2 text-xs hover:bg-gray-100 dark:hover:bg-gray-700/50 text-gray-700 dark:text-gray-200 flex items-center gap-2 group transition-colors"
                        >
                           <Bot className="w-3.5 h-3.5 text-gray-400 group-hover:text-primary-500" />
                           <span className="flex-1 truncate font-mono">{option}</span>
                           {value === option && <Check className="w-3.5 h-3.5 text-primary-500" />}
                        </button>
                    ))}
                </div>
            ) : (
                 <div className="px-3 py-2 text-xs text-gray-400 italic">
                    {emptyMessage}
                </div>
            )}
        </div>
      )}
    </div>
  );
};

export const APP_VERSION = '1.5.3';

export enum Role {
  USER = 'user',
  MODEL = 'model'
}

export interface Message {
  id: string;
  role: Role;
  text: string;
  images?: string[]; // Array of base64 data URIs
  timestamp: number;
  isError?: boolean;
  keyIndex?: number; // 1-based index of the key used
  provider?: ModelProvider; // Track which provider generated this
  model?: string; // The specific model used for this message
  executionTime?: number; // Time taken to generate response in ms
  groupName?: string; // Name of the group the key belonged to
}

export interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
  createdAt: number;
}

export type ModelProvider = 'google' | 'openai' | 'ollama';

export interface KeyGroup {
  id: string;
  name: string;
  isActive?: boolean; // Controls whether the group is enabled during polling
}

export interface KeyConfig {
  id: string;
  key: string;
  provider: ModelProvider; 
  label?: string;
  isActive: boolean;
  usageLimit: number; // Number of requests before switching
  isRateLimited: boolean;
  lastUsed: number;
  baseUrl?: string; // Specific Base URL for this key (OpenAI)
  model?: string;   // Specific Model for this key
  lastErrorCode?: string; // Code of the last error encountered
  groupId?: string; // Optional: ID of the group this key belongs to
}

export enum GeminiModel {
  FLASH = 'gemini-2.5-flash',
  PRO = 'gemini-3-pro-preview',
  FLASH_THINKING = 'gemini-2.5-flash-thinking-preview-01-21',
  IMAGEN = 'imagen-3.0-generate-001'
}

export interface ModelInfo {
  name: string;
  displayName?: string;
  inputTokenLimit?: number;
  outputTokenLimit?: number;
}

export interface SystemPrompt {
  id: string;
  title: string;
  content: string;
  isActive: boolean;
}

export type Theme = 'light' | 'dark' | 'twilight' | 'sky' | 'pink' | 'sunrise' | 'lime' | 'panda' | 'chocolate' | 'vscode-light' | 'vscode-dark';
export type Language = 'en' | 'zh' | 'ja';
export type TextWrappingMode = 'default' | 'forced' | 'auto';
export type AvatarVisibility = 'always' | 'user-only' | 'model-only' | 'never';

export interface SecurityQuestion {
  id: string;
  question: string;
  answer: string;
}

export interface SecurityConfig {
  enabled: boolean;
  password?: string;
  questions: SecurityQuestion[];
  lastLogin: number;
  lockoutDurationSeconds?: number; // New: Duration in seconds for inactivity lockout
}

export interface GenerationConfig {
  temperature: number;
  topP: number;
  topK: number;
  maxOutputTokens: number;
  stream: boolean;
  thinkingBudget?: number; // New: For Gemini 2.5 thinking models
  stripThoughts?: boolean; // New: Strip <think> tags from history to save tokens
}

export interface ScriptConfig {
  inputFilterEnabled: boolean;
  inputFilterCode: string; // The content of the js/ts file
  inputFileName?: string;
  outputFilterEnabled: boolean;
  outputFilterCode: string; // The content of the js/ts file
  outputFileName?: string;
}

export interface AppSettings {
  // Removed global 'model' and 'openAIBaseUrl' as they are now per-key or defaults for new keys
  defaultModel: string; // Default model for new keys
  defaultBaseUrl: string; // Default URL for new OpenAI keys

  systemPrompts: SystemPrompt[];
  theme: Theme;
  language: Language;
  fontSize: number; 
  textWrapping: TextWrappingMode;
  avatarVisibility: AvatarVisibility; // New: Control avatar visibility
  bubbleTransparency: number; // 0-100
  showModelName: boolean; // New: Toggle model name visibility
  showGroupName: boolean; // New: Toggle group name visibility
  kirbyThemeColor: boolean; // New: Toggle kirby icon theme adaptation
  showTokenUsage: boolean; // New: Toggle token usage estimation
  showResponseTimer: boolean; // New: Toggle response execution time display
  smoothAnimation: boolean; // New: Toggle typewriter animation
  historyContextLimit: number; // New: Limit number of past messages sent (0 = unlimited)
  security: SecurityConfig;
  generation: GenerationConfig;
  scripts: ScriptConfig; // New: Script settings

  // API Key Grouping
  enableKeyGrouping?: boolean;
  keyGroups?: KeyGroup[];

  // knownModels removed from AppSettings to separate cache from configuration
  savedModels?: string[]; // Deprecated, kept for interface compat if needed, but logic moved to keys
}

export interface ToastMessage {
  id: string;
  message: string;
  type: 'success' | 'error' | 'info';
}

export interface DialogConfig {
  isOpen: boolean;
  type: 'alert' | 'confirm' | 'input';
  title: string;
  message?: string;
  inputValue?: string;
  inputPlaceholder?: string;
  onConfirm: (value?: string) => void;
  onCancel?: () => void;
}

"use client";

import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { LLMService } from './services/llmService';
import { Message, Role, GeminiModel, AppSettings, KeyConfig, ChatSession, ModelProvider, APP_VERSION, ToastMessage, DialogConfig, ModelInfo } from './types';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import { Header } from './components/Header';
import ChatInput from './components/ChatInput';
import { t } from './utils/i18n';
import { ToastContainer } from './components/ui/Toast';
import { CustomDialog } from './components/ui/CustomDialog';
import { executeFilterScript } from './utils/scriptExecutor';

const SettingsModal = lazy(() => import('./components/SettingsModal'));
const SecurityLock = lazy(() => import('./components/SecurityLock'));
const MobileMenu = lazy(() => import('./components/MobileMenu'));

const DEFAULT_MODEL = 'gemini-3-flash-preview';
const STORAGE_KEYS_KEY = 'gemini_omnichat_keys_v4';
const STORAGE_SETTINGS_KEY = 'gemini_omnichat_settings_v8'; 
const STORAGE_SESSIONS_KEY = 'gemini_omnichat_sessions_v1';
const STORAGE_ACTIVE_SESSION_KEY = 'gemini_omnichat_active_session_v1';
const STORAGE_KNOWN_MODELS_KEY = 'gemini_omnichat_known_models_v1';

const ENV_KEY = process.env.API_KEY || '';

const DEFAULT_KNOWN_MODELS: ModelInfo[] = [
    { name: 'gemini-3-flash-preview', inputTokenLimit: 1048576, outputTokenLimit: 8192 },
    { name: 'gemini-3-pro-preview', inputTokenLimit: 2097152, outputTokenLimit: 8192 }
];

const App: React.FC = () => {
  // --- 状态定义 ---
  const [sessions, setSessions] = useState<ChatSession[]>([]); // 会话列表
  const [activeSessionId, setActiveSessionId] = useState<string>(''); // 当前活动会话 ID
  const [messages, setMessages] = useState<Message[]>([]); // 当前会话的消息记录
  const [input, setInput] = useState(''); // 输入框文本
  const [inputImages, setInputImages] = useState<string[]>([]); // 待发送的图片
  const [isLoading, setIsLoading] = useState(false); // 是否正在生成回复
  const [isSummarizing, setIsSummarizing] = useState(false); // 是否正在总结标题
  const [isSettingsOpen, setIsSettingsOpen] = useState(false); // 设置弹窗开关
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false); // 移动端侧边栏开关
  const [isLocked, setIsLocked] = useState(false); // 隐私安全锁状态
  const [apiKeys, setApiKeys] = useState<KeyConfig[]>([]); // API 密钥池
  const [knownModels, setKnownModels] = useState<ModelInfo[]>(DEFAULT_KNOWN_MODELS); // 已知模型缓存

  // --- 应用配置 ---
  const [settings, setSettings] = useState<AppSettings>({
    defaultModel: DEFAULT_MODEL,
    defaultBaseUrl: 'https://api.openai.com/v1',
    systemPrompts: [],
    theme: 'light', 
    language: 'zh', 
    fontSize: 14,
    textWrapping: 'auto', 
    bubbleTransparency: 100, 
    showModelName: true, 
    showGroupName: false,
    kirbyThemeColor: false, 
    showTokenUsage: false, 
    showResponseTimer: false, 
    smoothAnimation: true, 
    avatarVisibility: 'always', 
    historyContextLimit: 0, 
    security: {
        enabled: false,
        questions: [],
        lastLogin: Date.now(),
        lockoutDurationSeconds: 86400 
    },
    generation: {
        temperature: 1.0,
        topP: 0.95,
        topK: 40,
        maxOutputTokens: 8192,
        stream: false, 
        thinkingBudget: 0, 
        stripThoughts: false 
    },
    scripts: {
        inputFilterEnabled: false,
        inputFilterCode: '',
        outputFilterEnabled: false,
        outputFilterCode: ''
    },
    enableKeyGrouping: false,
    keyGroups: []
  });

  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [dialog, setDialog] = useState<DialogConfig>({
      isOpen: false,
      type: 'alert',
      title: '',
      onConfirm: () => {}
  });

  const [llmService, setLlmService] = useState<LLMService | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const isProcessingRef = useRef(false);

  // --- 辅助工具函数 ---
  const addToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
      setToasts(prev => [...prev, { id: uuidv4(), message, type }]);
  };

  const removeToast = (id: string) => {
      setToasts(prev => prev.filter(t => t.id !== id));
  };

  const showDialog = (config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => {
      setDialog({
          isOpen: true,
          type: config.type || 'alert',
          title: config.title,
          message: config.message,
          inputValue: config.inputValue,
          inputPlaceholder: config.inputPlaceholder,
          onConfirm: config.onConfirm,
          onCancel: config.onCancel
      });
  };

  const closeDialog = () => {
      setDialog(prev => ({ ...prev, isOpen: false }));
  };

  const safeJsonParse = (str: string | null, fallback: any = null) => {
    if (!str || !str.trim()) return fallback;
    try {
      return JSON.parse(str);
    } catch (e) {
      console.warn("Failed to parse JSON from storage:", e);
      return fallback;
    }
  };

  /**
   * 节点 1: 挂载初始化
   * 从 LocalStorage 加载所有持久化数据，包括密钥、设置和会话历史。
   */
  useEffect(() => {
    const storedKeys = localStorage.getItem(STORAGE_KEYS_KEY);
    const oldKeysV3 = localStorage.getItem('gemini_omnichat_keys_v3');
    const oldSettingsStr = localStorage.getItem('gemini_omnichat_settings_v5');
    const oldSettings = safeJsonParse(oldSettingsStr);
    const globalModel = oldSettings?.model || DEFAULT_MODEL;
    const globalBaseUrl = oldSettings?.openAIBaseUrl || 'https://api.openai.com/v1';

    let initialKeys: KeyConfig[] = [];

    if (storedKeys) {
      initialKeys = safeJsonParse(storedKeys, []);
    } else if (oldKeysV3) {
      const parsed = safeJsonParse(oldKeysV3, []);
      initialKeys = parsed.map((k: any) => ({
          ...k,
          model: globalModel,
          baseUrl: k.provider === 'openai' ? globalBaseUrl : ''
      }));
    } else if (ENV_KEY) {
      initialKeys = ENV_KEY.split(',').map(k => k.trim()).filter(Boolean).map(k => ({
        id: uuidv4(),
        key: k,
        provider: 'google' as ModelProvider,
        isActive: true,
        usageLimit: 5, 
        isRateLimited: false,
        lastUsed: 0,
        model: DEFAULT_MODEL
      }));
    }
    setApiKeys(initialKeys);

    const storedSettings = localStorage.getItem(STORAGE_SETTINGS_KEY);
    let loadedSettings = settings;
    let loadedKnownModels = DEFAULT_KNOWN_MODELS;

    const storedKnownModels = localStorage.getItem(STORAGE_KNOWN_MODELS_KEY);
    if (storedKnownModels) {
        // Merge stored models with defaults to ensure new defaults appear
        const parsedStoredModels = safeJsonParse(storedKnownModels, []);
        // Create a map for easy lookup by name
        const storedModelMap = new Map(parsedStoredModels.map((m: any) => [m.name, m]));

        // Start with defaults
        const mergedModels = [...DEFAULT_KNOWN_MODELS];

        // Add any stored models that are NOT in defaults
        parsedStoredModels.forEach((m: any) => {
            if (!mergedModels.find(dm => dm.name === m.name)) {
                mergedModels.push(m);
            }
        });

        loadedKnownModels = mergedModels;
    }

    if (storedSettings) {
      const parsedSettings = safeJsonParse(storedSettings);
      if (parsedSettings) {
          if (parsedSettings.knownModels && !storedKnownModels) {
              loadedKnownModels = parsedSettings.knownModels;
          }
          if ('knownModels' in parsedSettings) delete parsedSettings.knownModels;
          loadedSettings = { ...settings, ...parsedSettings };
      }
    } 
    setSettings(loadedSettings);
    setKnownModels(loadedKnownModels);

    const effectiveKeys = initialKeys.map(k => {
        if (!k.groupId) return k;
        const group = loadedSettings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    // 初始化核心 LLM 服务
    setLlmService(new LLMService(effectiveKeys, (id, errorCode, isFatal = true) => {
        setApiKeys(prev => prev.map(k => {
            if (k.id !== id) return k;
            if (isFatal) return { ...k, isActive: false, lastErrorCode: errorCode };
            else return { ...k, isRateLimited: true, lastUsed: Date.now(), lastErrorCode: errorCode };
        }));
        if (isFatal) addToast(`${t('error.key_auto_disabled', loadedSettings.language)}${errorCode ? ` (${errorCode})` : ''}`, 'error');
    }));

    // 安全锁检查
    if (loadedSettings.security.enabled) {
        const lockoutThresholdMs = (loadedSettings.security.lockoutDurationSeconds || 86400) * 1000;
        if (Date.now() - (loadedSettings.security.lastLogin || 0) > lockoutThresholdMs) setIsLocked(true);
        else setSettings({ ...loadedSettings, security: { ...loadedSettings.security, lastLogin: Date.now() } });
    }

    // 会话恢复
    const storedSessions = localStorage.getItem(STORAGE_SESSIONS_KEY);
    const storedActiveId = localStorage.getItem(STORAGE_ACTIVE_SESSION_KEY);

    if (storedSessions) {
      const parsedSessions = safeJsonParse(storedSessions, []) as ChatSession[];
      if (parsedSessions.length > 0) {
        setSessions(parsedSessions);
        const targetId = (storedActiveId && parsedSessions.find(s => s.id === storedActiveId)) ? storedActiveId : parsedSessions[0].id;
        setActiveSessionId(targetId);
        setMessages(parsedSessions.find(s => s.id === targetId)?.messages || []);
      } else createNewSession();
    } else createNewSession();
  }, []);

  const createNewSession = () => {
    const newId = uuidv4();
    const newSession: ChatSession = {
      id: newId,
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newId);
    setMessages([]);
  };

  /**
   * 节点 2: 数据同步
   * 监听状态变动并同步至服务层或持久化存储。
   */
  useEffect(() => {
    const effectiveKeys = apiKeys.map(k => {
        if (!k.groupId) return k;
        const group = settings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    if (llmService) llmService.updateKeys(effectiveKeys);
    localStorage.setItem(STORAGE_KEYS_KEY, JSON.stringify(apiKeys));
  }, [apiKeys, llmService, settings.keyGroups]);

  useEffect(() => {
    localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(settings));
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-chocolate', 'theme-vscode-light', 'theme-vscode-dark');
    root.classList.add(`theme-${settings.theme}`);
    if (['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme)) root.classList.add('dark');
  }, [settings]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KNOWN_MODELS_KEY, JSON.stringify(knownModels));
  }, [knownModels]);

  useEffect(() => {
    if (!activeSessionId) return;
    setSessions(prev => {
      const idx = prev.findIndex(s => s.id === activeSessionId);
      if (idx === -1) return prev;
      const updated = [...prev];
      updated[idx] = { ...updated[idx], messages };
      return updated;
    });
  }, [messages, activeSessionId]);

  useEffect(() => {
    if (sessions.length > 0) localStorage.setItem(STORAGE_SESSIONS_KEY, JSON.stringify(sessions));
  }, [sessions]);

  useEffect(() => {
    if (activeSessionId) localStorage.setItem(STORAGE_ACTIVE_SESSION_KEY, activeSessionId);
  }, [activeSessionId]);

  /**
   * 节点 3: 消息处理逻辑
   * 处理流式响应并将其分片渲染至 UI。
   */
  const triggerBotResponse = async (historyBefore: Message[], userMessage: Message) => {
    if (!llmService) return;
    setIsLoading(true);

    if (abortControllerRef.current) abortControllerRef.current.abort();
    const controller = new AbortController();
    abortControllerRef.current = controller;

    const tempBotId = uuidv4();
    const botMessage: Message = {
      id: tempBotId,
      role: Role.MODEL,
      text: '',
      timestamp: Date.now()
    };

    setMessages([...historyBefore, userMessage, botMessage]);

    const startTime = Date.now();

    try {
      const systemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');
      let historyForApi = historyBefore.filter(m => m.id !== userMessage.id);

      if (settings.generation.stripThoughts) {
        historyForApi = historyForApi.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }

      let contextToSend = historyForApi;
      if (settings.historyContextLimit > 0 && historyForApi.length > settings.historyContextLimit) {
          contextToSend = historyForApi.slice(-settings.historyContextLimit);
      }

      // 执行流式调用
      const { text: fullText, usedKeyIndex, provider, usedModel } = await llmService.streamChatResponse(
        '', 
        contextToSend, 
        userMessage.text, 
        userMessage.images, 
        systemInstruction,
        settings.generation,
        (chunkText) => {
           let processedChunk = chunkText;
           if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
               processedChunk = executeFilterScript(settings.scripts.outputFilterCode, chunkText, { role: 'model', history: [...historyBefore, userMessage] });
           }
           setMessages(prev => prev.map(msg => msg.id === tempBotId ? { ...msg, text: processedChunk } : msg));
        },
        controller.signal,
        settings.language
      );

      const executionTime = Date.now() - startTime;
      let processedFinalText = fullText;

      if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
          processedFinalText = executeFilterScript(settings.scripts.outputFilterCode, fullText, { role: 'model', history: [...historyBefore, userMessage] });
      }

      // Resolve Group Name
      let groupName: string | undefined;
      if (usedKeyIndex && usedKeyIndex > 0 && usedKeyIndex <= apiKeys.length) {
          const usedKey = apiKeys[usedKeyIndex - 1];
          if (usedKey && usedKey.groupId) {
              const group = settings.keyGroups?.find(g => g.id === usedKey.groupId);
              if (group) groupName = group.name;
          }
      }

      setMessages(prev => 
        prev.map(msg => 
          msg.id === tempBotId ? { 
              ...msg, 
              text: processedFinalText, 
              keyIndex: usedKeyIndex, 
              provider: provider, 
              model: usedModel, 
              executionTime: executionTime,
              groupName: groupName
          } : msg
        )
      );
    } catch (error: any) {
      if (error.message !== "Aborted by user") {
         const errorMessage: Message = {
            id: uuidv4(),
            role: Role.MODEL,
            text: `${t('action.error', settings.language)}: ${error.message || t('error.unexpected_error', settings.language)}`,
            timestamp: Date.now(),
            isError: true,
            executionTime: Date.now() - startTime
         };
         setMessages(prev => prev.filter(m => m.id !== tempBotId).concat(errorMessage));
      }
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGeneration = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
          abortControllerRef.current = null;
          setIsLoading(false);
      }
  };

  const handleSendMessage = async () => {
    if (!llmService || isProcessingRef.current) return;
    if (!input.trim() && inputImages.length === 0) return;

    if (apiKeys.filter(k => k.isActive).length === 0) {
      setIsSettingsOpen(true);
      return;
    }

    isProcessingRef.current = true; 

    let processedInput = input.trim();
    if (settings.scripts?.inputFilterEnabled && settings.scripts.inputFilterCode) {
        processedInput = executeFilterScript(settings.scripts.inputFilterCode, processedInput, { role: 'user', history: messages });
    }

    const newMessage: Message = {
      id: uuidv4(),
      role: Role.USER,
      text: processedInput,
      images: inputImages.length > 0 ? [...inputImages] : undefined, 
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newMessage]);
    setInput('');
    setInputImages([]); 

    try {
        await triggerBotResponse(messages, newMessage);
    } finally {
        isProcessingRef.current = false; 
    }
  };

  /**
   * 节点 4: 加载对话功能修复与增强
   * 将对话作为新会话导入，而不是覆盖当前会话，避免用户误操作。
   */
  const handleLoadSession = (loadedMessages: any[], title?: string) => {
      handleStopGeneration();

      // 生成新的会话对象
      const newId = uuidv4();
      const newSession: ChatSession = {
          id: newId,
          title: title || t('msg.new_chat_title', settings.language),
          messages: loadedMessages,
          createdAt: Date.now()
      };

      // 插入到会话列表最前端并立即切换
      setSessions(prev => [newSession, ...prev]);
      setActiveSessionId(newId);
      setMessages(loadedMessages);
      setInput('');

      // 使用更明确的“对话已导入”提示
      addToast(t('success.chat_import', settings.language) || t('msg.config_imported', settings.language), 'success');
  };

  const handleSaveChat = () => {
    const activeSession = sessions.find(s => s.id === activeSessionId);
    const title = activeSession?.title || t('label.session', settings.language);
    const safeTitle = title.replace(/[^a-z0-9\u4e00-\u9fa5]/gi, '_').substring(0, 50);
    const chatData = { title, date: new Date().toISOString(), messages };
    const blob = new Blob([JSON.stringify(chatData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `OmniChat-${safeTitle}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleSelectSession = (sessionId: string) => {
    if (sessionId === activeSessionId) { setIsMobileMenuOpen(false); return; }
    handleStopGeneration();
    const session = sessions.find(s => s.id === sessionId);
    if (session) {
      setActiveSessionId(sessionId);
      setMessages(session.messages);
      setInput('');
      setIsMobileMenuOpen(false);
    }
  };

  const activeKeysCount = apiKeys.filter(k => k.isActive).length;
  const currentSessionTitle = sessions.find(s => s.id === activeSessionId)?.title || t('app.title', settings.language);

  if (isLocked) return (
    <div className={`${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
        <Suspense fallback={<div className="flex h-screen items-center justify-center bg-gray-100 dark:bg-gray-950"></div>}>
            <SecurityLock config={settings.security} onUnlock={() => setIsLocked(false)} lang={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor} />
        </Suspense>
    </div>
  );

  return (
    <div className={`flex h-screen font-sans ${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <CustomDialog config={dialog} onClose={closeDialog} lang={settings.language} />

      <div className="flex w-full h-full bg-transparent text-gray-900 dark:text-gray-100 transition-colors duration-300">
        <Sidebar 
            sessions={sessions} activeSessionId={activeSessionId} activeKeysCount={activeKeysCount} 
            language={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor}
            onNewChat={() => { handleStopGeneration(); createNewSession(); setIsMobileMenuOpen(false); }} 
            onSelectSession={handleSelectSession} 
            onDeleteSession={(e, id) => {
                e.stopPropagation();
                const newSessions = sessions.filter(s => s.id !== id);
                setSessions(newSessions);
                if (activeSessionId === id) {
                   handleStopGeneration();
                   if (newSessions.length > 0) {
                     setActiveSessionId(newSessions[0].id);
                     setMessages(newSessions[0].messages);
                   } else createNewSession();
                }
            }}
            onOpenSettings={() => setIsSettingsOpen(true)}
        />

        <Suspense fallback={null}>
            <MobileMenu 
                isOpen={isMobileMenuOpen} sessions={sessions} activeSessionId={activeSessionId} language={settings.language}
                onClose={() => setIsMobileMenuOpen(false)} onNewChat={() => { handleStopGeneration(); createNewSession(); setIsMobileMenuOpen(false); }} 
                onSelectSession={handleSelectSession}
                onDeleteSession={(e, id) => {
                    e.stopPropagation();
                    const newSessions = sessions.filter(s => s.id !== id);
                    setSessions(newSessions);
                    if (activeSessionId === id) {
                       handleStopGeneration();
                       if (newSessions.length > 0) {
                         setActiveSessionId(newSessions[0].id);
                         setMessages(newSessions[0].messages);
                       } else createNewSession();
                    }
                }} 
                onOpenSettings={() => setIsSettingsOpen(true)}
            />
        </Suspense>

        <main className="flex-1 flex flex-col relative h-full min-w-0 overflow-hidden">
          <Header 
             currentSessionTitle={currentSessionTitle} isSummarizing={isSummarizing} hasMessages={messages.length > 0}
             language={settings.language} onRename={() => {
                const currentSession = sessions.find(s => s.id === activeSessionId);
                showDialog({
                    type: 'input',
                    title: t('msg.rename_chat', settings.language),
                    inputValue: currentSession?.title || '',
                    onConfirm: (newTitle) => {
                        if (newTitle && newTitle.trim()) setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle.trim() } : s));
                    }
                });
             }} 
             onSummarize={async () => {
                if (messages.length === 0 || !llmService) return;
                setIsSummarizing(true); 
                try {
                    const historyText = messages.map(m => `${m.role === Role.USER ? 'User' : 'Model'}: ${m.text}`).join('\n');
                    const prompt = t('msg.summarize_prompt', settings.language) + '\n\n' + historyText;
                    const { text } = await llmService.streamChatResponse('', [], prompt, [], undefined, settings.generation, undefined, undefined, settings.language);
                    const newTitle = text.trim().replace(/['"]/g, '').replace(/\.$/, '').replace(/\*\*/g, ''); 
                    if (newTitle) {
                        setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle } : s));
                        addToast(t('action.ok', settings.language), 'success');
                    }
                } catch (e) {
                    addToast(t('msg.summarize_error', settings.language), 'error');
                } finally { setIsSummarizing(false); }
             }}
             onOpenMobileMenu={() => setIsMobileMenuOpen(true)} 
             onNewChat={() => { handleStopGeneration(); createNewSession(); }} 
             onClearChat={() => {
                if (messages.length === 0) return;
                showDialog({
                    type: 'confirm',
                    title: t('action.clear_chat', settings.language),
                    message: t('msg.confirm_clear_chat', settings.language),
                    onConfirm: () => {
                        handleStopGeneration();
                        setMessages([]);
                        setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, messages: [] } : s));
                    }
                });
             }}
             onOpenSettings={() => setIsSettingsOpen(true)} 
             onSaveChat={handleSaveChat} 
             onLoadSession={handleLoadSession} 
             onShowToast={addToast}
          />

          <ChatInterface 
              messages={messages} isLoading={isLoading} 
              onEditMessage={(id, newText) => setMessages(prev => prev.map(msg => msg.id === id ? { ...msg, text: newText } : msg))} 
              onDeleteMessage={(id) => setMessages(prev => prev.filter(msg => msg.id !== id))} 
              onRegenerate={async (id) => {
                if (!llmService) return;
                const index = messages.findIndex(m => m.id === id);
                if (index === -1) return;
                const targetMsg = messages[index];
                if (targetMsg.role === Role.USER) {
                   await triggerBotResponse(messages.slice(0, index), targetMsg);
                } else {
                  let userMsgIndex = index - 1;
                  while (userMsgIndex >= 0 && messages[userMsgIndex].role !== Role.USER) userMsgIndex--;
                  if (userMsgIndex !== -1) await triggerBotResponse(messages.slice(0, userMsgIndex), messages[userMsgIndex]);
                }
              }} 
              language={settings.language} fontSize={settings.fontSize} 
              textWrapping={settings.textWrapping} bubbleTransparency={settings.bubbleTransparency}
              showModelName={settings.showModelName} showGroupName={settings.showGroupName} showResponseTimer={settings.showResponseTimer} theme={settings.theme}
              kirbyThemeColor={settings.kirbyThemeColor} onShowToast={addToast} smoothAnimation={settings.smoothAnimation}
              avatarVisibility={settings.avatarVisibility}
          />

          <div className="absolute bottom-0 left-0 right-0 z-20 bg-gradient-to-t from-white via-white to-transparent dark:from-gray-950 dark:via-gray-950 dark:to-transparent pt-10 pb-0">
             <ChatInput 
                input={input} setInput={setInput} inputImages={inputImages} setInputImages={setInputImages}
                onSend={handleSendMessage} onStop={handleStopGeneration} isLoading={isLoading} isDisabled={activeKeysCount === 0}
                fontSize={settings.fontSize} language={settings.language} activeKeysCount={activeKeysCount} showTokenUsage={settings.showTokenUsage}
                history={messages} historyLimit={settings.historyContextLimit} 
                onGetTokenCount={async (currentInput) => {
                    if (!llmService || apiKeys.length === 0) return 0;
                    const activeKey = apiKeys.find(k => k.isActive);
                    if (!activeKey) return 0;
                    return await llmService.countTokens(activeKey, messages, currentInput, settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n'));
                }} 
                theme={settings.theme}
             />
             <div className="text-center text-[10px] text-gray-400 dark:text-gray-600 pb-0 select-none">
                {t('footer.ai_generated', settings.language)}{APP_VERSION}
             </div>
          </div>
        </main>

        <Suspense fallback={null}>
            <SettingsModal 
                isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} apiKeys={apiKeys} onUpdateKeys={setApiKeys} 
                settings={settings} onUpdateSettings={setSettings} llmService={llmService} onShowToast={addToast}
                onShowDialog={showDialog} knownModels={knownModels} onUpdateKnownModels={setKnownModels}
            />
        </Suspense>
      </div>
    </div>
  );
};

export default App;

"use client";

import React, { useRef, useEffect, useState, useLayoutEffect, useCallback } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus, vs } from 'react-syntax-highlighter/dist/esm/styles/prism';
import { User, AlertCircle, Check, Copy, X, Save, Edit2, RefreshCw, Trash2, Clock, Brain, ChevronDown, ChevronRight, ExternalLink } from 'lucide-react';
import { Message, Role, Language, TextWrappingMode, Theme, AvatarVisibility } from '../types';
import { t } from '../utils/i18n';
import { KirbyIcon } from './Kirby';
import { ChatMessage } from './ChatMessage';

interface ChatInterfaceProps {
  messages: Message[];
  isLoading: boolean;
  onEditMessage: (id: string, newText: string) => void;
  onDeleteMessage: (id: string) => void;
  onRegenerate: (id: string) => void;
  language: Language;
  fontSize: number;
  textWrapping: TextWrappingMode;
  bubbleTransparency: number;
  showModelName: boolean;
  showGroupName?: boolean;
  showResponseTimer?: boolean;
  theme: Theme;
  kirbyThemeColor: boolean;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  smoothAnimation?: boolean;
  avatarVisibility: AvatarVisibility;
}

const LoadingTimer = () => {
  const [tenths, setTenths] = useState(0);

  useEffect(() => {
    const startTime = Date.now();
    const interval = setInterval(() => {
      const elapsed = Date.now() - startTime;
      setTenths(Math.floor(elapsed / 100));
    }, 100);
    return () => clearInterval(interval);
  }, []);

  return (
    <span className="text-xs font-mono text-primary-600 dark:text-primary-400 ml-2 select-none min-w-[3ch]">
      {(tenths / 10).toFixed(1)}s
    </span>
  );
};

const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
    messages, 
    isLoading, 
    onEditMessage, 
    onDeleteMessage, 
    onRegenerate, 
    language, 
    fontSize, 
    textWrapping, 
    bubbleTransparency, 
    showModelName,
    showGroupName,
    showResponseTimer = false,
    theme, 
    kirbyThemeColor,
    onShowToast,
    smoothAnimation = true,
    avatarVisibility
}) => {
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const deleteTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const [previewImageUrl, setPreviewImageUrl] = useState<string | null>(null);

  // Track if the user has manually scrolled up to pause auto-scrolling
  const isUserScrolledUp = useRef(false);
  const scrollRafId = useRef<number | null>(null);
  const lastIsLoading = useRef(isLoading);

  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl';

  // --- Scroll Logic ---

  // 1. Check if user is near bottom to enable/disable sticky mode
  const handleScroll = () => {
    if (!scrollContainerRef.current) return;
    const { scrollTop, scrollHeight, clientHeight } = scrollContainerRef.current;

    // Threshold to consider "at bottom". 
    // Small threshold (20px) ensures that if user scrolls up slightly, we respect it immediately (stop auto-scroll).
    const isAtBottom = scrollHeight - scrollTop - clientHeight < 20;

    // We strictly track this state to allow reading history while generating
    isUserScrolledUp.current = !isAtBottom;
  };

  // 2. Callback passed to ChatMessage to trigger scroll on text expansion
  // This ensures smooth scrolling even if the network request finished but animation is still playing
  const scrollToBottom = useCallback(() => {
     if (scrollContainerRef.current && !isUserScrolledUp.current) {
         // Force scroll to absolute bottom
         scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
     }
  }, []);

  // 3. Reset scroll lock when new messages are added (User sent one, or History loaded)
  useLayoutEffect(() => {
      isUserScrolledUp.current = false;
  }, [messages.length]);

  // 4. Initial Snap to Top on New Generation
  useLayoutEffect(() => {
    // Detect edge: isLoading goes false -> true (Start of generation)
    if (!lastIsLoading.current && isLoading) {
        // Reset user scroll lock
        isUserScrolledUp.current = false;

        // Find the AI message and snap it to top
        requestAnimationFrame(() => {
            if (scrollContainerRef.current) {
                const container = scrollContainerRef.current;
                const messageElements = container.querySelectorAll('[data-role="model"]');
                const lastModelMessage = messageElements[messageElements.length - 1];

                if (lastModelMessage) {
                    lastModelMessage.scrollIntoView({ block: 'start', behavior: 'smooth' });
                } else {
                    container.scrollTop = container.scrollHeight;
                }
            }
        });
    }
    lastIsLoading.current = isLoading;
  }, [isLoading]);


  // 5. The Sticky Loop (Bottom Tracking during loading)
  // This runs continuously while isLoading is true for network phase
  useEffect(() => {
    if (!isLoading) {
      if (scrollRafId.current) cancelAnimationFrame(scrollRafId.current);
      return;
    }

    const loop = () => {
      const container = scrollContainerRef.current;
      if (container && !isUserScrolledUp.current) {
        const { scrollHeight, scrollTop, clientHeight } = container;
        const distanceFromBottom = scrollHeight - (scrollTop + clientHeight);

        // Sticky logic: If content pushes down, follow it, but allow the "Snap to Top" gap
        // We only force scroll if the bottom is obscured by more than threshold
        if (distanceFromBottom > 20) {
            container.scrollTop = scrollHeight - clientHeight;
        }
      }
      scrollRafId.current = requestAnimationFrame(loop);
    };

    loop();

    return () => {
      if (scrollRafId.current) cancelAnimationFrame(scrollRafId.current);
    };
  }, [isLoading]);

  // 6. Fallback: Handle non-streaming loads
  useLayoutEffect(() => {
    if (!isLoading && scrollContainerRef.current && !isUserScrolledUp.current) {
       scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
    }
  }, [messages.length, isLoading]);

  useEffect(() => {
    return () => {
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
    };
  }, [messages]);

  const startEditing = (msg: Message) => { 
    setEditingId(msg.id); 
    setConfirmDeleteId(null);
  };

  // Calculate dynamic background color for loading bubble based on transparency
  // Note: structure and basic styles are now in CSS .loading-bubble
  const borderAlpha = 0.5 + (bubbleTransparency / 100) * 0.5;
  const dynamicStyle = {
      backgroundColor: `rgba(var(--color-theme-primary-rgb), ${(bubbleTransparency / 100) * 0.15})`,
      borderColor: isVSCodeTheme ? 'transparent' : `rgba(var(--color-theme-primary-rgb), ${borderAlpha})`
  };

  const showLoadingAvatar = avatarVisibility === 'always' || avatarVisibility === 'model-only';

  if (messages.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center px-4">
        <div className="w-48 h-48 mb-6 animate-fade-in-up">
            <KirbyIcon theme={theme} isThemed={kirbyThemeColor} />
        </div>
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">{t('app.title', language)}</h1>
        <p className="text-gray-600 dark:text-gray-400 max-w-md">{t('msg.welcome_desc', language)}</p>
      </div>
    );
  }

  return (
    <>
      <div 
          ref={scrollContainerRef}
          onScroll={handleScroll}
          // Use scrollbar-overlay class for floating scrollbar effect
          className="flex-1 scrollbar-overlay p-2 md:p-4 h-full relative"
      >
        <div className="flex flex-col space-y-4 pb-4 min-h-0">
          {messages.map((msg, index) => (
              <div key={msg.id} data-role={msg.role}>
                  <ChatMessage
                      msg={msg}
                      isEditing={editingId === msg.id}
                      isConfirmingDelete={confirmDeleteId === msg.id}
                      isLoading={isLoading}
                      bubbleTransparency={bubbleTransparency}
                      textWrapping={textWrapping}
                      fontSize={fontSize}
                      showModelName={showModelName}
                      showGroupName={showGroupName}
                      showResponseTimer={showResponseTimer}
                      language={language}
                      theme={theme}
                      kirbyThemeColor={kirbyThemeColor}
                      onEditMessage={onEditMessage}
                      onDeleteMessage={onDeleteMessage}
                      onRegenerate={onRegenerate}
                      setEditingId={setEditingId}
                      setConfirmDeleteId={setConfirmDeleteId}
                      startEditing={startEditing}
                      deleteTimerRef={deleteTimerRef}
                      onShowToast={onShowToast}
                      smoothAnimation={smoothAnimation}
                      isLast={index === messages.length - 1}
                      onScrollToBottom={scrollToBottom}
                      avatarVisibility={avatarVisibility}
                      onViewImage={setPreviewImageUrl}
                  />
              </div>
          ))}

          {isLoading && (
              <div className={`flex justify-start w-full ${containerClass} mx-auto animate-fade-in-up px-2 md:px-0`} data-role="loading">
              <div className="flex gap-3">
                  {showLoadingAvatar && (
                      <div className="flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center overflow-hidden">
                          <div className="w-full h-full scale-150">
                              <KirbyIcon theme={theme} isThemed={kirbyThemeColor} />
                          </div>
                      </div>
                  )}
                  <div 
                      className="loading-bubble"
                      style={dynamicStyle}
                  >
                      <div className="typing-dot" style={{ animationDelay: '0ms' }}></div>
                      <div className="typing-dot" style={{ animationDelay: '150ms' }}></div>
                      <div className="typing-dot" style={{ animationDelay: '300ms' }}></div>
                      {showResponseTimer && <LoadingTimer />}
                  </div>
              </div>
              </div>
          )}

          {/* Dynamic Bottom Buffer */}
          <div 
              className="w-full transition-all duration-300 ease-out flex-shrink-0" 
              style={{ height: isLoading ? '160px' : '128px' }} 
              aria-hidden="true" 
          />
        </div>
      </div>

      {/* Lightbox / Full Screen Image Preview */}
      {previewImageUrl && (
        <div 
          className="fixed inset-0 z-[300] bg-black/90 backdrop-blur-sm flex items-center justify-center p-4 cursor-zoom-out animate-fade-in-up"
          onClick={() => setPreviewImageUrl(null)}
        >
          <img 
            src={previewImageUrl} 
            alt="Full Screen Preview" 
            className="max-w-full max-h-full object-contain rounded-lg shadow-2xl"
            onClick={() => setPreviewImageUrl(null)} // Ensure clicking image also closes
          />
          <button 
            onClick={() => setPreviewImageUrl(null)}
            className="absolute top-4 right-4 text-white/70 hover:text-white p-2 rounded-full hover:bg-white/10 transition-colors"
          >
             <X className="w-8 h-8" />
          </button>
        </div>
      )}
    </>
  );
};

export default ChatInterface;

import React, { useRef, useState, useEffect, useLayoutEffect, useMemo } from 'react';
import { User, X, Save, Edit2, RefreshCw, Trash2, Clock, Folder } from 'lucide-react';
import { Message, Role, Language, TextWrappingMode, Theme, AvatarVisibility } from '../types';
import { t } from '../utils/i18n';
import { KirbyIcon } from './Kirby';
import { AutoResizeTextarea } from './ui/AutoResizeTextarea';
import { MessageContent } from './message/MessageContent';

interface ChatMessageProps {
  msg: Message;
  isEditing: boolean;
  isConfirmingDelete: boolean;
  isLoading: boolean;
  bubbleTransparency: number;
  textWrapping: TextWrappingMode;
  fontSize: number;
  showModelName: boolean;
  showGroupName?: boolean;
  showResponseTimer?: boolean;
  language: Language;
  theme: Theme;
  kirbyThemeColor: boolean;
  onEditMessage: (id: string, newText: string) => void;
  onDeleteMessage: (id: string) => void;
  onRegenerate: (id: string) => void;
  setEditingId: (id: string | null) => void;
  setConfirmDeleteId: (id: string | null) => void;
  startEditing: (msg: Message) => void;
  deleteTimerRef: React.MutableRefObject<ReturnType<typeof setTimeout> | null>;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  smoothAnimation?: boolean;
  isLast?: boolean;
  onScrollToBottom?: () => void;
  avatarVisibility: AvatarVisibility;
  onViewImage?: (url: string) => void;
}

export const ChatMessage: React.FC<ChatMessageProps> = React.memo(({
  msg,
  isEditing,
  isConfirmingDelete,
  isLoading,
  bubbleTransparency,
  textWrapping,
  fontSize,
  showModelName,
  showGroupName,
  showResponseTimer = false,
  language,
  theme,
  kirbyThemeColor,
  onEditMessage,
  onDeleteMessage,
  onRegenerate,
  setEditingId,
  setConfirmDeleteId,
  startEditing,
  deleteTimerRef,
  onShowToast,
  smoothAnimation = true,
  isLast = false,
  onScrollToBottom,
  avatarVisibility,
  onViewImage
}) => {
  const safeText = msg.text || '';
  const [editText, setEditText] = useState(safeText);
  const [displayedText, setDisplayedText] = useState(safeText);
  const targetTextRef = useRef(safeText);
  const animationRef = useRef<number>(0);

  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl';

  // 检测消息是否为生成的图片（Markdown 图片且包含 Data URI）
  // 对于生成的图片跳过动画，避免 base64 源码闪烁
  const isGeneratedImage = useMemo(() => {
      const trimmed = safeText.trim();
      return msg.role === Role.MODEL && trimmed.startsWith('![') && trimmed.includes('(data:image/');
  }, [safeText, msg.role]);

  // --- 动画逻辑 ---
  useEffect(() => {
    targetTextRef.current = safeText;
    // 如果关闭动画、不是 AI 消息、错误消息、正在编辑或生成的图片，则直接显示完整文本
    if (!smoothAnimation || msg.role !== Role.MODEL || isEditing || isGeneratedImage) {
        setDisplayedText(safeText);
    }
  }, [safeText, msg.role, isEditing, smoothAnimation, isGeneratedImage]);

  useEffect(() => {
    if (isEditing) setEditText(safeText);
  }, [isEditing, safeText]);

  /**
   * 打字机动画循环
   * 根据缓冲区待处理字符数动态调整打字速度
   */
  useEffect(() => {
    if (!smoothAnimation || msg.role !== Role.MODEL || msg.isError || isEditing || isGeneratedImage) return;

    const animate = () => {
      setDisplayedText((current) => {
        const target = targetTextRef.current;
        if (current === target) return current;
        if (current.length > target.length) return target;

        const diff = target.length - current.length;

        /**
         * 动态调整打字步长：
         * 根据用户需求，提高比例为缓冲区字数 (diff) / 50。
         * 设置最小步长为 1，确保即使剩余字数较少也能匀速完成渲染。
         */
        const chunk = Math.max(1, Math.ceil(diff / 50));

        const nextLen = Math.min(target.length, current.length + chunk);
        const nextText = target.substring(0, nextLen);
        return nextText;
      });
      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);
    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [msg.role, msg.isError, isEditing, smoothAnimation, isGeneratedImage]);

  useLayoutEffect(() => {
      if (isLast && onScrollToBottom && smoothAnimation && msg.role === Role.MODEL && !isEditing && !isGeneratedImage) {
          onScrollToBottom();
      }
  }, [displayedText, isLast, onScrollToBottom, smoothAnimation, msg.role, isEditing, isGeneratedImage]);

  // --- 处理方法 ---

  const cancelEditing = () => { 
    setEditingId(null); 
    setEditText(''); 
    setConfirmDeleteId(null);
  };

  const saveEdit = () => { 
    if (editText.trim() !== safeText) onEditMessage(msg.id, editText); 
    setEditingId(null); 
    setConfirmDeleteId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => { 
    if (e.key === 'Enter' && !e.shiftKey) { 
      e.preventDefault(); 
      saveEdit(); 
    } 
    if (e.key === 'Escape') cancelEditing(); 
  };

  const handleDeleteClick = () => {
    setEditingId(null);
    if (isConfirmingDelete) {
      onDeleteMessage(msg.id);
      setConfirmDeleteId(null);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
    } else {
      setConfirmDeleteId(msg.id);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
      deleteTimerRef.current = setTimeout(() => {
        setConfirmDeleteId(null);
        deleteTimerRef.current = null;
      }, 3000);
    }
  };

  const handleRegenerateClick = () => {
    onRegenerate(msg.id);
    setConfirmDeleteId(null);
  }

  const handleImageClick = (src: string) => {
      if (onViewImage) {
          onViewImage(src);
      } else {
          window.open(src, '_blank');
      }
  };

  // --- 样式计算 ---

  const effectiveTransparency = isEditing ? 100 : bubbleTransparency;
  const borderAlpha = 0.5 + (effectiveTransparency / 100) * 0.5;
  const shadowAlpha = (100 - effectiveTransparency) / 100;

  const textShadowStyle = effectiveTransparency < 90 
    ? `0 1px 2px rgba(var(--color-theme-primary-rgb), ${shadowAlpha})` 
    : 'none';

  let backgroundColor;
  if (msg.role === Role.USER) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${effectiveTransparency / 100})`;
  } else if (msg.role === Role.MODEL && !msg.isError) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${(effectiveTransparency / 100) * 0.15})`;
  }

  const animationClass = smoothAnimation ? 'animate-pop-in' : '';
  const wrapperWidthClass = isEditing ? 'w-full max-w-full' : 'max-w-[95%] md:max-w-[85%]'; 
  const bubbleBorderColor = isVSCodeTheme ? 'transparent' : `rgba(var(--color-theme-primary-rgb), ${borderAlpha})`;

  const showAvatar = 
    avatarVisibility === 'always' || 
    (avatarVisibility === 'user-only' && msg.role === Role.USER) ||
    (avatarVisibility === 'model-only' && msg.role === Role.MODEL);

  return (
    <div className={`flex w-full ${containerClass} mx-auto ${msg.role === Role.USER ? 'justify-end' : 'justify-start'} animate-fade-in-up group`}>
        <div className={`flex gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} ${wrapperWidthClass}`}>

            {showAvatar && (
                <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center mt-0.5 overflow-hidden ${msg.role === Role.USER ? 'bg-primary-600' : 'bg-transparent'} ${msg.isError ? 'bg-red-500' : ''}`}>
                    {msg.role === Role.USER ? <User className="w-5 h-5 text-white" /> : <div className="w-full h-full scale-150"><KirbyIcon theme={theme} isThemed={kirbyThemeColor} /></div>}
                </div>
            )}

            <div className={`flex flex-col min-w-0 ${msg.role === Role.USER ? 'items-end' : 'items-start'} w-full`}>
            <div 
                className={`relative px-3 py-2.5 rounded-2xl shadow-sm backdrop-blur-sm transition-all duration-300 w-full max-w-full origin-bottom-left ${animationClass} ${
                    msg.role === Role.USER 
                    ? 'text-white rounded-tr-sm border origin-bottom-right' 
                    : msg.isError 
                        ? 'bg-red-100 dark:bg-red-900/30 border border-red-200 dark:border-red-800 text-red-800 dark:text-red-200 rounded-tl-sm' 
                        : 'border text-gray-800 dark:text-gray-100 rounded-tl-sm'
                }`}
                style={
                    !msg.isError ? { 
                        backgroundColor,
                        borderColor: bubbleBorderColor,
                        textShadow: textShadowStyle
                    } : {}
                }
            >
                {/* 消息附件图片网格 */}
                {msg.images && msg.images.length > 0 && !isEditing && (
                    <div className="flex flex-wrap gap-2 mb-2">
                        {msg.images.map((img, idx) => (
                            <div key={idx} className="relative group">
                                <img 
                                    src={img} 
                                    alt="Message Attachment" 
                                    className="max-h-64 max-w-full rounded-lg cursor-pointer hover:opacity-90 transition-opacity" 
                                    onClick={() => handleImageClick(img)}
                                />
                            </div>
                        ))}
                    </div>
                )}

                {isEditing ? (
                <div className="w-full min-w-[200px]">
                    <AutoResizeTextarea 
                        value={editText} 
                        onChange={(e) => setEditText(e.target.value)} 
                        onKeyDown={handleKeyDown} 
                        fontSize={fontSize}
                        autoFocus
                        lang={language}
                    />
                    <div className="flex justify-end gap-2 mt-2">
                        <button 
                        onClick={cancelEditing} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.cancel', language)}
                        aria-label={t('action.cancel_edit', language)}
                    >
                            <X className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                        <button 
                        onClick={saveEdit} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.confirm', language)}
                        aria-label={t('action.save_edit', language)}
                    >
                            <Save className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                    </div>
                </div>
                ) : (
                    <MessageContent 
                        content={displayedText}
                        role={msg.role}
                        isError={msg.isError}
                        images={msg.images}
                        textWrapping={textWrapping}
                        fontSize={fontSize}
                        language={language}
                        theme={theme}
                        onShowToast={onShowToast}
                        onViewImage={onViewImage}
                        isLast={isLast} // Pass isLast to control auto-expansion of thoughts
                    />
                )}
            </div>

            <div className="flex flex-wrap items-center gap-x-2 gap-y-1 mt-1 px-1 min-h-[1.5rem]">
                <span className="text-[10px] text-gray-400 dark:text-gray-500 whitespace-nowrap">{new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                {msg.role === Role.MODEL && !msg.isError && (
                <div className="flex flex-wrap items-center gap-1">
                    {msg.keyIndex && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title={t('tooltip.key_index', language)}>#{msg.keyIndex}</span>
                    )}
                    {showGroupName && msg.groupName && (
                        <div className="flex items-center gap-0.5 text-[10px] font-mono bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 px-1 rounded border border-indigo-100 dark:border-indigo-800 whitespace-nowrap" title={t('tooltip.group_name', language)}>
                            <Folder className="w-2.5 h-2.5" />
                            <span>{msg.groupName}</span>
                        </div>
                    )}
                    {showModelName && msg.model && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 break-all max-w-[250px]" title={t('tooltip.model_used', language)}>{msg.model}</span>
                    )}
                    {showResponseTimer && msg.executionTime && (
                        <div className="flex items-center gap-0.5 text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title={t('tooltip.response_time', language)}>
                            <Clock className="w-2.5 h-2.5" />
                            <span>{t('label.response_time', language).replace('{duration}', (msg.executionTime / 1000).toFixed(1))}</span>
                        </div>
                    )}
                </div>
                )}
                {!isLoading && !isEditing && (
                <div className={`flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity`}>
                    <button 
                    onClick={() => startEditing(msg)} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={t('action.edit', language)}
                    aria-label={t('action.edit_message', language)}
                    >
                    <Edit2 className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleRegenerateClick} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={msg.role === Role.USER ? t('action.regenerate_from_user_message', language) : t('action.regenerate_response', language)}
                    aria-label={t('action.regenerate', language)}
                    >
                    <RefreshCw className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleDeleteClick} 
                    className={`p-4 md:p-1 transition-colors ${isConfirmingDelete ? 'text-red-500 bg-red-50 dark:bg-red-900/20 rounded' : 'text-gray-400 hover:text-red-500'}`}
                    title={isConfirmingDelete ? t('action.confirm_delete', language) : t('action.delete', language)}
                    aria-label={t('action.delete_message', language)}
                    >
                    <Trash2 className="w-3.5 h-3.5" />
                    </button>
                </div>
                )}
            </div>
            </div>
        </div>
    </div>
  );
}, (prev, next) => {
  return (
    prev.msg === next.msg &&
    prev.isEditing === next.isEditing &&
    prev.isConfirmingDelete === next.isConfirmingDelete &&
    prev.isLoading === next.isLoading &&
    prev.bubbleTransparency === next.bubbleTransparency &&
    prev.textWrapping === next.textWrapping &&
    prev.fontSize === next.fontSize &&
    prev.showModelName === next.showModelName &&
    prev.showGroupName === next.showGroupName &&
    prev.showResponseTimer === next.showResponseTimer &&
    prev.language === next.language &&
    prev.theme === next.theme &&
    prev.kirbyThemeColor === next.kirbyThemeColor &&
    prev.smoothAnimation === next.smoothAnimation &&
    prev.isLast === next.isLast &&
    prev.avatarVisibility === next.avatarVisibility
  );
});

import { Message, KeyConfig, GenerationConfig, ModelProvider, ModelInfo, Language, KeyGroup } from "../types";
import { OpenAIService } from "./openaiService";
import { GoogleService } from "./googleService";
import { OllamaService } from "./ollamaService";
import { t } from "../utils/i18n";

/**
 * 队列任务接口定义
 */
interface RequestTask {
  execute: () => Promise<any>;
  resolve: (value: any) => void;
  reject: (reason?: any) => void;
  abortSignal?: AbortSignal;
}

interface LLMServiceCallbacks {
    onKeyError?: (id: string, errorCode?: string, isFatal?: boolean) => void;
    onStatusMessage?: (message: string, type: 'info' | 'warning' | 'error' | 'success') => void;
}

/**
 * LLM 核心服务类：处理多提供商交互。
 * 包含：API 密钥轮询、负载均衡、请求队列处理。
 */
export class LLMService {
  private keys: KeyConfig[] = [];
  private keyGroups: KeyGroup[] = [];
  private keyIndex: number = 0; // 当前轮询到的 Key 索引
  private keyUsageCount: number = 0; // 当前 Key 已使用的次数

  // 队列管理状态：确保 API 请求按顺序处理，避免高并发冲突
  private requestQueue: RequestTask[] = [];
  private isProcessingQueue: boolean = false;

  private openAIService: OpenAIService;
  private googleService: GoogleService;
  private ollamaService: OllamaService;

  private onKeyError?: (id: string, errorCode?: string, isFatal?: boolean) => void;
  private onStatusMessage?: (message: string, type: 'info' | 'warning' | 'error' | 'success') => void;

  constructor(
      initialKeys: KeyConfig[], 
      callbacksOrOnError?: LLMServiceCallbacks | ((id: string, errorCode?: string, isFatal?: boolean) => void)
  ) {
    this.updateKeys(initialKeys);
    this.openAIService = new OpenAIService();
    this.googleService = new GoogleService();
    this.ollamaService = new OllamaService();

    if (typeof callbacksOrOnError === 'function') {
        this.onKeyError = callbacksOrOnError;
    } else if (callbacksOrOnError) {
        this.onKeyError = callbacksOrOnError.onKeyError;
        this.onStatusMessage = callbacksOrOnError.onStatusMessage;
    }
  }

  /**
   * 更新 API 密钥池
   */
  public updateKeys(newKeys: KeyConfig[], keyGroups: KeyGroup[] = []) {
    this.keys = newKeys;
    this.keyGroups = keyGroups;
    // 索引越界安全检查
    if (this.keyIndex >= this.keys.length) {
        this.keyIndex = 0;
        this.keyUsageCount = 0;
    }
  }

  private getGroupName(groupId?: string): string | undefined {
    if (!groupId) return undefined;
    return this.keyGroups.find(g => g.id === groupId)?.name;
  }

  /**
   * 将任务推入队列并触发处理逻辑
   */
  private async enqueueTask<T>(execute: () => Promise<T>, abortSignal?: AbortSignal): Promise<T> {
    return new Promise((resolve, reject) => {
      if (abortSignal?.aborted) {
        return reject(new Error("Aborted by user"));
      }

      this.requestQueue.push({
        execute,
        resolve,
        reject,
        abortSignal
      });

      this.processQueue();
    });
  }

  /**
   * 顺序处理队列中的任务 (FIFO)
   */
  private async processQueue() {
    if (this.isProcessingQueue || this.requestQueue.length === 0) return;

    this.isProcessingQueue = true;

    while (this.requestQueue.length > 0) {
      const task = this.requestQueue.shift();
      if (!task) continue;

      if (task.abortSignal?.aborted) {
        task.reject(new Error("Aborted by user"));
        continue;
      }

      try {
        const result = await task.execute();
        task.resolve(result);
      } catch (error) {
        task.reject(error);
      }
    }

    this.isProcessingQueue = false;
  }

  /**
   * 获取模型列表
   */
  public async listModels(keyConfig: KeyConfig): Promise<ModelInfo[]> {
    return this.enqueueTask(async () => {
      if (keyConfig.provider === 'openai') {
          if (!keyConfig.baseUrl) throw new Error("Base URL is required for OpenAI provider");
          return await this.openAIService.listModels(keyConfig.key, keyConfig.baseUrl);
      } else if (keyConfig.provider === 'ollama') {
          return await this.ollamaService.listModels(keyConfig.baseUrl || '', keyConfig.key);
      } else {
          return await this.googleService.listModels(keyConfig.key);
      }
    });
  }

  /**
   * 测试连接
   */
  public async testConnection(keyConfig: KeyConfig): Promise<boolean> {
    return this.enqueueTask(async () => {
      const modelToUse = keyConfig.model || (keyConfig.provider === 'openai' ? 'gpt-3.5-turbo' : 'gemini-2.5-flash');
      try {
          if (keyConfig.provider === 'openai') {
              if (!keyConfig.baseUrl) return false;
              return await this.openAIService.testChat(keyConfig.key, keyConfig.baseUrl, modelToUse);
          } else if (keyConfig.provider === 'ollama') {
              return await this.ollamaService.testConnection(keyConfig.baseUrl || '', keyConfig.key);
          } else {
              return await this.googleService.testConnection(keyConfig.key, modelToUse);
          }
      } catch (e) {
          return false;
      }
    });
  }

  /**
   * 核心算法：轮询策略
   * 寻找下一个可用的 API 密钥，考虑：活跃状态、速率限制冷却时间、单个 Key 的轮询配额。
   */
  private getNextAvailableKey(lang: Language): KeyConfig {
    const activeKeys = this.keys.filter(k => k.isActive);

    if (activeKeys.length === 0) {
      throw new Error(t('error.no_active_keys', lang));
    }

    const attempts = activeKeys.length;
    let selectedKey: KeyConfig | null = null;
    let selectedIndex = -1;

    for (let i = 0; i < attempts; i++) {
        const idx = (this.keyIndex + i) % activeKeys.length;
        const candidate = activeKeys[idx];

        // 检查冷却时间：如果被 429 限制，进入 1 分钟冷却期
        if (candidate.isRateLimited && Date.now() - candidate.lastUsed < 60000) {
            continue; 
        }

        // 检查轮询配额：如果当前 Key 还没用够设定的次数，继续用它
        if (i === 0 && this.keyUsageCount < (candidate.usageLimit || 1)) {
             selectedKey = candidate;
             selectedIndex = idx;
             break;
        }

        // 切换到下一个 Key
        if (i > 0) {
            selectedKey = candidate;
            selectedIndex = idx;
            break;
        }
    }

    // 如果所有 Key 都因为某种原因被跳过，强制选择当前索引的下一个
    if (!selectedKey) {
        selectedIndex = (this.keyIndex + 1) % activeKeys.length;
        selectedKey = activeKeys[selectedIndex];
    }

    // 如果发生了索引切换，重置单密钥使用计数
    if (this.keyIndex !== selectedIndex) {
        this.keyIndex = selectedIndex;
        this.keyUsageCount = 0;
    }

    this.keyUsageCount++;
    return selectedKey;
  }

  private getKeyDisplayIndex(id: string): number {
      return this.keys.findIndex(k => k.id === id) + 1;
  }

  /**
   * 错误分级处理逻辑
   * 将 API 返回的原始错误转化为用户可读的本地化语言。
   */
  private getErrorMessage(error: any, lang: Language): string {
      const status = error.status || error.statusCode;
      const msg = error.message?.toLowerCase() || '';

      if (status === 401 || msg.includes('401') || msg.includes('invalid api key')) return t('error.invalid_api_key', lang);
      if (status === 402 || msg.includes('402') || msg.includes('billing')) return t('error.billing_required', lang);
      if (status === 403 || msg.includes('403') || msg.includes('permission denied')) return t('error.permission_denied', lang);
      if (status === 404 || msg.includes('404') || msg.includes('not found')) return t('error.model_not_found', lang);
      if (status === 429 || msg.includes('429') || msg.includes('quota') || msg.includes('rate limit')) return t('error.quota_exceeded', lang);
      if (status === 400 || msg.includes('400')) {
          if (msg.includes('safety') || error.isSafety) return t('error.safety_block', lang);
          if (msg.includes('context')) return t('error.context_length_exceeded', lang);
          return t('error.bad_request', lang);
      }
      if (status === 500 || status === 502 || status === 503 || msg.includes('500')) return t('error.server_error', lang);
      if (status === 0 || msg.includes('network') || msg.includes('fetch')) return t('error.network_issue', lang);

      return error.message || t('error.unexpected_error', lang);
  }

  /**
   * 节点 5: 核心重试与分发逻辑
   * 在发生非致命错误（如速率限制）时自动切换密钥并重试。
   */
  public async streamChatResponse(
    _ignoredGlobalModelId: string, 
    history: Message[],
    newMessage: string,
    images: string[] | undefined,
    systemInstruction: string | undefined,
    generationConfig: GenerationConfig,
    onChunk?: (text: string) => void,
    abortSignal?: AbortSignal,
    lang: Language = 'en'
  ): Promise<{ text: string, usedKeyIndex: number, provider: ModelProvider, usedModel: string }> {

    return this.enqueueTask(async () => {
        const activeKeysCount = this.keys.filter(k => k.isActive).length;
        // 最大重试次数为活跃密钥数的 2 倍
        const maxRetries = Math.max(activeKeysCount * 2, 2); 
        let attempts = 0;
        const validHistory = history.filter(msg => (msg.text && msg.text.trim().length > 0) || (msg.images && msg.images.length > 0));

        let lastError: any = null;
        let lastGroupId: string | undefined = undefined;

        while (attempts < maxRetries) {
            let keyConfig: KeyConfig;
            try {
                keyConfig = this.getNextAvailableKey(lang);
            } catch (e: any) {
                throw e;
            }

            const currentKeyIndex = this.getKeyDisplayIndex(keyConfig.id);
            const currentGroupId = keyConfig.groupId;
            const groupName = this.getGroupName(currentGroupId);

            // Notify on switch (Retry or Rotation)
            // Skip notification for the very first attempt unless debugging, to be less noisy? 
            // The prompt asks for "Every key switch", so we include retries.
            if (attempts > 0) {
                let msg = t('msg.switching_key', lang).replace('{index}', currentKeyIndex.toString());
                // Detect Group Switch specifically
                if (currentGroupId && lastGroupId && currentGroupId !== lastGroupId && groupName) {
                     msg += ` (${t('msg.switching_group', lang).replace('{group}', groupName)})`;
                }
                this.onStatusMessage?.(msg, 'info');
            }

            lastGroupId = currentGroupId;

            const modelToUse = keyConfig.model || _ignoredGlobalModelId || 'gemini-3-flash-preview';

            try {
                let text = "";

                // 根据提供商分发请求
                if (keyConfig.provider === 'google' && modelToUse.toLowerCase().includes('imagen')) {
                     text = await this.googleService.generateImage(keyConfig.key, modelToUse, newMessage);
                } 
                else if (keyConfig.provider === 'openai') {
                    if (!keyConfig.baseUrl) throw new Error(t('error.base_url_required', lang));
                    text = await this.openAIService.streamChat(
                        keyConfig.key, keyConfig.baseUrl, modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, onChunk, abortSignal
                    );
                } 
                else if (keyConfig.provider === 'ollama') {
                    text = await this.ollamaService.streamChat(
                        keyConfig.baseUrl || '', modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, keyConfig.key, onChunk, abortSignal
                    );
                } 
                else {
                    text = await this.googleService.streamChat(
                        keyConfig.key, modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, onChunk, abortSignal
                    );
                }

                return { 
                    text, 
                    usedKeyIndex: currentKeyIndex, 
                    provider: keyConfig.provider,
                    usedModel: modelToUse
                };

            } catch (error: any) {
                if (abortSignal?.aborted) throw new Error("Aborted by user");

                lastError = error;
                let errorCode = 'Error';
                let statusCode = error.status || error.statusCode;

                if (!statusCode) {
                     const match = error.message?.match(/\b\d{3}\b/);
                     if (match) errorCode = match[0];
                     else if (error.message?.includes("Network")) errorCode = "Network";
                } else {
                    errorCode = statusCode.toString();
                }

                // Notify Error before switching
                const errorMessage = this.getErrorMessage(error, lang);
                this.onStatusMessage?.(
                    t('msg.key_error_verbose', lang)
                        .replace('{index}', currentKeyIndex.toString())
                        .replace('{error}', errorMessage), 
                    'error'
                );

                // 判断是否是致命错误：身份验证失败、计费问题、位置不支持等需要禁用密钥
                let isFatal = [401, 402, 403, 404].includes(statusCode);

                // 安全审核拦截不属于密钥问题，直接抛出给用户
                if (error.isSafety) {
                    throw new Error(this.getErrorMessage(error, lang));
                }

                if (this.onKeyError) {
                    this.onKeyError(keyConfig.id, errorCode, isFatal);
                }

                const localKey = this.keys.find(k => k.id === keyConfig.id);
                if (localKey) {
                    if (isFatal) localKey.isActive = false;
                    else {
                        // 速率限制错误：进入冷却
                        localKey.isRateLimited = true;
                        localKey.lastUsed = Date.now();
                        // 强制轮询配额用满，以便下次重试使用新 Key
                        this.keyUsageCount = 10000; 
                    }
                    localKey.lastErrorCode = errorCode;
                }

                if (this.keys.filter(k => k.isActive).length === 0) break; 

                attempts++;
                continue;
            }
        }

        if (lastError) throw new Error(this.getErrorMessage(lastError, lang));
        throw new Error(t('error.all_keys_failed', lang));
    }, abortSignal);
  }

  /**
   * Token 统计
   */
  public async countTokens(
      keyConfig: KeyConfig,
      history: Message[],
      newMessage: string,
      _ignoredSystemInstruction: string | undefined
  ): Promise<number> {
      return this.enqueueTask(async () => {
          if (keyConfig.provider !== 'google') return -1;
          return await this.googleService.countTokens(
              keyConfig.key, keyConfig.model || 'gemini-3-flash-preview', history, newMessage
          );
      });
  }
}

"use client";

import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { LLMService } from './services/llmService';
import { Message, Role, GeminiModel, AppSettings, KeyConfig, ChatSession, ModelProvider, APP_VERSION, ToastMessage, DialogConfig, ModelInfo } from './types';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import { Header } from './components/Header';
import ChatInput from './components/ChatInput';
import { t } from './utils/i18n';
import { ToastContainer } from './components/ui/Toast';
import { CustomDialog } from './components/ui/CustomDialog';
import { executeFilterScript } from './utils/scriptExecutor';

const SettingsModal = lazy(() => import('./components/SettingsModal'));
const SecurityLock = lazy(() => import('./components/SecurityLock'));
const MobileMenu = lazy(() => import('./components/MobileMenu'));

const DEFAULT_MODEL = 'gemini-3-flash-preview';
const STORAGE_KEYS_KEY = 'gemini_omnichat_keys_v4';
const STORAGE_SETTINGS_KEY = 'gemini_omnichat_settings_v8'; 
const STORAGE_SESSIONS_KEY = 'gemini_omnichat_sessions_v1';
const STORAGE_ACTIVE_SESSION_KEY = 'gemini_omnichat_active_session_v1';
const STORAGE_KNOWN_MODELS_KEY = 'gemini_omnichat_known_models_v1';

const ENV_KEY = process.env.API_KEY || '';

const DEFAULT_KNOWN_MODELS: ModelInfo[] = [
    { name: 'gemini-3-flash-preview', inputTokenLimit: 1048576, outputTokenLimit: 8192 },
    { name: 'gemini-3-pro-preview', inputTokenLimit: 2097152, outputTokenLimit: 8192 }
];

const App: React.FC = () => {
  // --- 状态定义 ---
  const [sessions, setSessions] = useState<ChatSession[]>([]); // 会话列表
  const [activeSessionId, setActiveSessionId] = useState<string>(''); // 当前活动会话 ID
  const [messages, setMessages] = useState<Message[]>([]); // 当前会话的消息记录
  const [input, setInput] = useState(''); // 输入框文本
  const [inputImages, setInputImages] = useState<string[]>([]); // 待发送的图片
  const [isLoading, setIsLoading] = useState(false); // 是否正在生成回复
  const [isSummarizing, setIsSummarizing] = useState(false); // 是否正在总结标题
  const [isSettingsOpen, setIsSettingsOpen] = useState(false); // 设置弹窗开关
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false); // 移动端侧边栏开关
  const [isLocked, setIsLocked] = useState(false); // 隐私安全锁状态
  const [apiKeys, setApiKeys] = useState<KeyConfig[]>([]); // API 密钥池
  const [knownModels, setKnownModels] = useState<ModelInfo[]>(DEFAULT_KNOWN_MODELS); // 已知模型缓存

  // --- 应用配置 ---
  const [settings, setSettings] = useState<AppSettings>({
    defaultModel: DEFAULT_MODEL,
    defaultBaseUrl: 'https://api.openai.com/v1',
    systemPrompts: [],
    theme: 'light', 
    language: 'zh', 
    fontSize: 14,
    textWrapping: 'auto', 
    bubbleTransparency: 100, 
    showModelName: true, 
    showGroupName: false,
    kirbyThemeColor: false, 
    showTokenUsage: false, 
    showResponseTimer: false, 
    smoothAnimation: true, 
    avatarVisibility: 'always', 
    historyContextLimit: 0, 
    security: {
        enabled: false,
        questions: [],
        lastLogin: Date.now(),
        lockoutDurationSeconds: 86400 
    },
    generation: {
        temperature: 1.0,
        topP: 0.95,
        topK: 40,
        maxOutputTokens: 8192,
        stream: false, 
        thinkingBudget: 0, 
        stripThoughts: false 
    },
    scripts: {
        inputFilterEnabled: false,
        inputFilterCode: '',
        outputFilterEnabled: false,
        outputFilterCode: ''
    },
    enableKeyGrouping: false,
    keyGroups: []
  });

  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [dialog, setDialog] = useState<DialogConfig>({
      isOpen: false,
      type: 'alert',
      title: '',
      onConfirm: () => {}
  });

  const [llmService, setLlmService] = useState<LLMService | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const isProcessingRef = useRef(false);

  // --- 辅助工具函数 ---
  const addToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
      setToasts(prev => [...prev, { id: uuidv4(), message, type }]);
  };

  const removeToast = (id: string) => {
      setToasts(prev => prev.filter(t => t.id !== id));
  };

  const showDialog = (config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => {
      setDialog({
          isOpen: true,
          type: config.type || 'alert',
          title: config.title,
          message: config.message,
          inputValue: config.inputValue,
          inputPlaceholder: config.inputPlaceholder,
          onConfirm: config.onConfirm,
          onCancel: config.onCancel
      });
  };

  const closeDialog = () => {
      setDialog(prev => ({ ...prev, isOpen: false }));
  };

  const safeJsonParse = (str: string | null, fallback: any = null) => {
    if (!str || !str.trim()) return fallback;
    try {
      return JSON.parse(str);
    } catch (e) {
      console.warn("Failed to parse JSON from storage:", e);
      return fallback;
    }
  };

  /**
   * 节点 1: 挂载初始化
   * 从 LocalStorage 加载所有持久化数据，包括密钥、设置和会话历史。
   */
  useEffect(() => {
    const storedKeys = localStorage.getItem(STORAGE_KEYS_KEY);
    const oldKeysV3 = localStorage.getItem('gemini_omnichat_keys_v3');
    const oldSettingsStr = localStorage.getItem('gemini_omnichat_settings_v5');
    const oldSettings = safeJsonParse(oldSettingsStr);
    const globalModel = oldSettings?.model || DEFAULT_MODEL;
    const globalBaseUrl = oldSettings?.openAIBaseUrl || 'https://api.openai.com/v1';

    let initialKeys: KeyConfig[] = [];

    if (storedKeys) {
      initialKeys = safeJsonParse(storedKeys, []);
    } else if (oldKeysV3) {
      const parsed = safeJsonParse(oldKeysV3, []);
      initialKeys = parsed.map((k: any) => ({
          ...k,
          model: globalModel,
          baseUrl: k.provider === 'openai' ? globalBaseUrl : ''
      }));
    } else if (ENV_KEY) {
      initialKeys = ENV_KEY.split(',').map(k => k.trim()).filter(Boolean).map(k => ({
        id: uuidv4(),
        key: k,
        provider: 'google' as ModelProvider,
        isActive: true,
        usageLimit: 5, 
        isRateLimited: false,
        lastUsed: 0,
        model: DEFAULT_MODEL
      }));
    }
    setApiKeys(initialKeys);

    const storedSettings = localStorage.getItem(STORAGE_SETTINGS_KEY);
    let loadedSettings = settings;
    let loadedKnownModels = DEFAULT_KNOWN_MODELS;

    const storedKnownModels = localStorage.getItem(STORAGE_KNOWN_MODELS_KEY);
    if (storedKnownModels) {
        // Merge stored models with defaults to ensure new defaults appear
        const parsedStoredModels = safeJsonParse(storedKnownModels, []);
        // Create a map for easy lookup by name
        const storedModelMap = new Map(parsedStoredModels.map((m: any) => [m.name, m]));

        // Start with defaults
        const mergedModels = [...DEFAULT_KNOWN_MODELS];

        // Add any stored models that are NOT in defaults
        parsedStoredModels.forEach((m: any) => {
            if (!mergedModels.find(dm => dm.name === m.name)) {
                mergedModels.push(m);
            }
        });

        loadedKnownModels = mergedModels;
    }

    if (storedSettings) {
      const parsedSettings = safeJsonParse(storedSettings);
      if (parsedSettings) {
          if (parsedSettings.knownModels && !storedKnownModels) {
              loadedKnownModels = parsedSettings.knownModels;
          }
          if ('knownModels' in parsedSettings) delete parsedSettings.knownModels;
          loadedSettings = { ...settings, ...parsedSettings };
      }
    } 
    setSettings(loadedSettings);
    setKnownModels(loadedKnownModels);

    const effectiveKeys = initialKeys.map(k => {
        if (!k.groupId) return k;
        const group = loadedSettings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    // 初始化核心 LLM 服务
    setLlmService(new LLMService(
        effectiveKeys, 
        {
            onKeyError: (id, errorCode, isFatal = true) => {
                setApiKeys(prev => prev.map(k => {
                    if (k.id !== id) return k;
                    if (isFatal) return { ...k, isActive: false, lastErrorCode: errorCode };
                    else return { ...k, isRateLimited: true, lastUsed: Date.now(), lastErrorCode: errorCode };
                }));
                // Only toast on fatal errors here, LLMService handles other status messages
                if (isFatal) addToast(`${t('error.key_auto_disabled', loadedSettings.language)}${errorCode ? ` (${errorCode})` : ''}`, 'error');
            },
            onStatusMessage: (msg, type) => addToast(msg, type)
        }
    ));

    // 安全锁检查
    if (loadedSettings.security.enabled) {
        const lockoutThresholdMs = (loadedSettings.security.lockoutDurationSeconds || 86400) * 1000;
        if (Date.now() - (loadedSettings.security.lastLogin || 0) > lockoutThresholdMs) setIsLocked(true);
        else setSettings({ ...loadedSettings, security: { ...loadedSettings.security, lastLogin: Date.now() } });
    }

    // 会话恢复
    const storedSessions = localStorage.getItem(STORAGE_SESSIONS_KEY);
    const storedActiveId = localStorage.getItem(STORAGE_ACTIVE_SESSION_KEY);

    if (storedSessions) {
      const parsedSessions = safeJsonParse(storedSessions, []) as ChatSession[];
      if (parsedSessions.length > 0) {
        setSessions(parsedSessions);
        const targetId = (storedActiveId && parsedSessions.find(s => s.id === storedActiveId)) ? storedActiveId : parsedSessions[0].id;
        setActiveSessionId(targetId);
        setMessages(parsedSessions.find(s => s.id === targetId)?.messages || []);
      } else createNewSession();
    } else createNewSession();
  }, []);

  const createNewSession = () => {
    const newId = uuidv4();
    const newSession: ChatSession = {
      id: newId,
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newId);
    setMessages([]);
  };

  /**
   * 节点 2: 数据同步
   * 监听状态变动并同步至服务层或持久化存储。
   */
  useEffect(() => {
    const effectiveKeys = apiKeys.map(k => {
        if (!k.groupId) return k;
        const group = settings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    if (llmService) llmService.updateKeys(effectiveKeys, settings.keyGroups || []);
    localStorage.setItem(STORAGE_KEYS_KEY, JSON.stringify(apiKeys));
  }, [apiKeys, llmService, settings.keyGroups]);

  useEffect(() => {
    localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(settings));
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-chocolate', 'theme-vscode-light', 'theme-vscode-dark');
    root.classList.add(`theme-${settings.theme}`);
    if (['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme)) root.classList.add('dark');
  }, [settings]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KNOWN_MODELS_KEY, JSON.stringify(knownModels));
  }, [knownModels]);

  useEffect(() => {
    if (!activeSessionId) return;
    setSessions(prev => {
      const idx = prev.findIndex(s => s.id === activeSessionId);
      if (idx === -1) return prev;
      const updated = [...prev];
      updated[idx] = { ...updated[idx], messages };
      return updated;
    });
  }, [messages, activeSessionId]);

  useEffect(() => {
    if (sessions.length > 0) localStorage.setItem(STORAGE_SESSIONS_KEY, JSON.stringify(sessions));
  }, [sessions]);

  useEffect(() => {
    if (activeSessionId) localStorage.setItem(STORAGE_ACTIVE_SESSION_KEY, activeSessionId);
  }, [activeSessionId]);

  /**
   * 节点 3: 消息处理逻辑
   * 处理流式响应并将其分片渲染至 UI。
   */
  const triggerBotResponse = async (historyBefore: Message[], userMessage: Message) => {
    if (!llmService) return;
    setIsLoading(true);

    if (abortControllerRef.current) abortControllerRef.current.abort();
    const controller = new AbortController();
    abortControllerRef.current = controller;

    const tempBotId = uuidv4();
    const botMessage: Message = {
      id: tempBotId,
      role: Role.MODEL,
      text: '',
      timestamp: Date.now()
    };

    setMessages([...historyBefore, userMessage, botMessage]);

    const startTime = Date.now();

    try {
      const systemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');
      let historyForApi = historyBefore.filter(m => m.id !== userMessage.id);

      if (settings.generation.stripThoughts) {
        historyForApi = historyForApi.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }

      let contextToSend = historyForApi;
      if (settings.historyContextLimit > 0 && historyForApi.length > settings.historyContextLimit) {
          contextToSend = historyForApi.slice(-settings.historyContextLimit);
      }

      // 执行流式调用
      const { text: fullText, usedKeyIndex, provider, usedModel } = await llmService.streamChatResponse(
        '', 
        contextToSend, 
        userMessage.text, 
        userMessage.images, 
        systemInstruction,
        settings.generation,
        (chunkText) => {
           let processedChunk = chunkText;
           if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
               processedChunk = executeFilterScript(settings.scripts.outputFilterCode, chunkText, { role: 'model', history: [...historyBefore, userMessage] });
           }
           setMessages(prev => prev.map(msg => msg.id === tempBotId ? { ...msg, text: processedChunk } : msg));
        },
        controller.signal,
        settings.language
      );

      const executionTime = Date.now() - startTime;
      let processedFinalText = fullText;

      if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
          processedFinalText = executeFilterScript(settings.scripts.outputFilterCode, fullText, { role: 'model', history: [...historyBefore, userMessage] });
      }

      // Resolve Group Name
      let groupName: string | undefined;
      if (usedKeyIndex && usedKeyIndex > 0 && usedKeyIndex <= apiKeys.length) {
          const usedKey = apiKeys[usedKeyIndex - 1];
          if (usedKey && usedKey.groupId) {
              const group = settings.keyGroups?.find(g => g.id === usedKey.groupId);
              if (group) groupName = group.name;
          }
      }

      setMessages(prev => 
        prev.map(msg => 
          msg.id === tempBotId ? { 
              ...msg, 
              text: processedFinalText, 
              keyIndex: usedKeyIndex, 
              provider: provider, 
              model: usedModel, 
              executionTime: executionTime,
              groupName: groupName
          } : msg
        )
      );
    } catch (error: any) {
      if (error.message !== "Aborted by user") {
         const errorMessage: Message = {
            id: uuidv4(),
            role: Role.MODEL,
            text: `${t('action.error', settings.language)}: ${error.message || t('error.unexpected_error', settings.language)}`,
            timestamp: Date.now(),
            isError: true,
            executionTime: Date.now() - startTime
         };
         setMessages(prev => prev.filter(m => m.id !== tempBotId).concat(errorMessage));
      }
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGeneration = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
          abortControllerRef.current = null;
          setIsLoading(false);
      }
  };

  const handleSendMessage = async () => {
    if (!llmService || isProcessingRef.current) return;
    if (!input.trim() && inputImages.length === 0) return;

    if (apiKeys.filter(k => k.isActive).length === 0) {
      setIsSettingsOpen(true);
      return;
    }

    isProcessingRef.current = true; 

    let processedInput = input.trim();
    if (settings.scripts?.inputFilterEnabled && settings.scripts.inputFilterCode) {
        processedInput = executeFilterScript(settings.scripts.inputFilterCode, processedInput, { role: 'user', history: messages });
    }

    const newMessage: Message = {
      id: uuidv4(),
      role: Role.USER,
      text: processedInput,
      images: inputImages.length > 0 ? [...inputImages] : undefined, 
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newMessage]);
    setInput('');
    setInputImages([]); 

    try {
        await triggerBotResponse(messages, newMessage);
    } finally {
        isProcessingRef.current = false; 
    }
  };

  /**
   * 节点 4: 加载对话功能修复与增强
   * 将对话作为新会话导入，而不是覆盖当前会话，避免用户误操作。
   */
  const handleLoadSession = (loadedMessages: any[], title?: string) => {
      handleStopGeneration();

      // 生成新的会话对象
      const newId = uuidv4();
      const newSession: ChatSession = {
          id: newId,
          title: title || t('msg.new_chat_title', settings.language),
          messages: loadedMessages,
          createdAt: Date.now()
      };

      // 插入到会话列表最前端并立即切换
      setSessions(prev => [newSession, ...prev]);
      setActiveSessionId(newId);
      setMessages(loadedMessages);
      setInput('');

      // 使用更明确的“对话已导入”提示
      addToast(t('success.chat_import', settings.language) || t('msg.config_imported', settings.language), 'success');
  };

  const handleSaveChat = () => {
    const activeSession = sessions.find(s => s.id === activeSessionId);
    const title = activeSession?.title || t('label.session', settings.language);
    const safeTitle = title.replace(/[^a-z0-9\u4e00-\u9fa5]/gi, '_').substring(0, 50);
    const chatData = { title, date: new Date().toISOString(), messages };
    const blob = new Blob([JSON.stringify(chatData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `OmniChat-${safeTitle}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleSelectSession = (sessionId: string) => {
    if (sessionId === activeSessionId) { setIsMobileMenuOpen(false); return; }
    handleStopGeneration();
    const session = sessions.find(s => s.id === sessionId);
    if (session) {
      setActiveSessionId(sessionId);
      setMessages(session.messages);
      setInput('');
      setIsMobileMenuOpen(false);
    }
  };

  const activeKeysCount = apiKeys.filter(k => k.isActive).length;
  const currentSessionTitle = sessions.find(s => s.id === activeSessionId)?.title || t('app.title', settings.language);

  if (isLocked) return (
    <div className={`${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
        <Suspense fallback={<div className="flex h-screen items-center justify-center bg-gray-100 dark:bg-gray-950"></div>}>
            <SecurityLock config={settings.security} onUnlock={() => setIsLocked(false)} lang={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor} />
        </Suspense>
    </div>
  );

  return (
    <div className={`flex h-screen font-sans ${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <CustomDialog config={dialog} onClose={closeDialog} lang={settings.language} />

      <div className="flex w-full h-full bg-transparent text-gray-900 dark:text-gray-100 transition-colors duration-300">
        <Sidebar 
            sessions={sessions} activeSessionId={activeSessionId} activeKeysCount={activeKeysCount} 
            language={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor}
            onNewChat={() => { handleStopGeneration(); createNewSession(); setIsMobileMenuOpen(false); }} 
            onSelectSession={handleSelectSession} 
            onDeleteSession={(e, id) => {
                e.stopPropagation();
                const newSessions = sessions.filter(s => s.id !== id);
                setSessions(newSessions);
                if (activeSessionId === id) {
                   handleStopGeneration();
                   if (newSessions.length > 0) {
                     setActiveSessionId(newSessions[0].id);
                     setMessages(newSessions[0].messages);
                   } else createNewSession();
                }
            }}
            onOpenSettings={() => setIsSettingsOpen(true)}
        />

        <Suspense fallback={null}>
            <MobileMenu 
                isOpen={isMobileMenuOpen} sessions={sessions} activeSessionId={activeSessionId} language={settings.language}
                onClose={() => setIsMobileMenuOpen(false)} onNewChat={() => { handleStopGeneration(); createNewSession(); setIsMobileMenuOpen(false); }} 
                onSelectSession={handleSelectSession}
                onDeleteSession={(e, id) => {
                    e.stopPropagation();
                    const newSessions = sessions.filter(s => s.id !== id);
                    setSessions(newSessions);
                    if (activeSessionId === id) {
                       handleStopGeneration();
                       if (newSessions.length > 0) {
                         setActiveSessionId(newSessions[0].id);
                         setMessages(newSessions[0].messages);
                       } else createNewSession();
                    }
                }} 
                onOpenSettings={() => setIsSettingsOpen(true)}
            />
        </Suspense>

        <main className="flex-1 flex flex-col relative h-full min-w-0 overflow-hidden">
          <Header 
             currentSessionTitle={currentSessionTitle} isSummarizing={isSummarizing} hasMessages={messages.length > 0}
             language={settings.language} onRename={() => {
                const currentSession = sessions.find(s => s.id === activeSessionId);
                showDialog({
                    type: 'input',
                    title: t('msg.rename_chat', settings.language),
                    inputValue: currentSession?.title || '',
                    onConfirm: (newTitle) => {
                        if (newTitle && newTitle.trim()) setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle.trim() } : s));
                    }
                });
             }} 
             onSummarize={async () => {
                if (messages.length === 0 || !llmService) return;
                setIsSummarizing(true); 
                try {
                    const historyText = messages.map(m => `${m.role === Role.USER ? 'User' : 'Model'}: ${m.text}`).join('\n');
                    const prompt = t('msg.summarize_prompt', settings.language) + '\n\n' + historyText;
                    const { text } = await llmService.streamChatResponse('', [], prompt, [], undefined, settings.generation, undefined, undefined, settings.language);
                    const newTitle = text.trim().replace(/['"]/g, '').replace(/\.$/, '').replace(/\*\*/g, ''); 
                    if (newTitle) {
                        setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle } : s));
                        addToast(t('action.ok', settings.language), 'success');
                    }
                } catch (e) {
                    addToast(t('msg.summarize_error', settings.language), 'error');
                } finally { setIsSummarizing(false); }
             }}
             onOpenMobileMenu={() => setIsMobileMenuOpen(true)} 
             onNewChat={() => { handleStopGeneration(); createNewSession(); }} 
             onClearChat={() => {
                if (messages.length === 0) return;
                showDialog({
                    type: 'confirm',
                    title: t('action.clear_chat', settings.language),
                    message: t('msg.confirm_clear_chat', settings.language),
                    onConfirm: () => {
                        handleStopGeneration();
                        setMessages([]);
                        setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, messages: [] } : s));
                    }
                });
             }}
             onOpenSettings={() => setIsSettingsOpen(true)} 
             onSaveChat={handleSaveChat} 
             onLoadSession={handleLoadSession} 
             onShowToast={addToast}
          />

          <ChatInterface 
              messages={messages} isLoading={isLoading} 
              onEditMessage={(id, newText) => setMessages(prev => prev.map(msg => msg.id === id ? { ...msg, text: newText } : msg))} 
              onDeleteMessage={(id) => setMessages(prev => prev.filter(msg => msg.id !== id))} 
              onRegenerate={async (id) => {
                if (!llmService) return;
                const index = messages.findIndex(m => m.id === id);
                if (index === -1) return;
                const targetMsg = messages[index];
                if (targetMsg.role === Role.USER) {
                   await triggerBotResponse(messages.slice(0, index), targetMsg);
                } else {
                  let userMsgIndex = index - 1;
                  while (userMsgIndex >= 0 && messages[userMsgIndex].role !== Role.USER) userMsgIndex--;
                  if (userMsgIndex !== -1) await triggerBotResponse(messages.slice(0, userMsgIndex), messages[userMsgIndex]);
                }
              }} 
              language={settings.language} fontSize={settings.fontSize} 
              textWrapping={settings.textWrapping} bubbleTransparency={settings.bubbleTransparency}
              showModelName={settings.showModelName} showGroupName={settings.showGroupName} showResponseTimer={settings.showResponseTimer} theme={settings.theme}
              kirbyThemeColor={settings.kirbyThemeColor} onShowToast={addToast} smoothAnimation={settings.smoothAnimation}
              avatarVisibility={settings.avatarVisibility}
          />

          <div className="absolute bottom-0 left-0 right-0 z-20 bg-gradient-to-t from-white via-white to-transparent dark:from-gray-950 dark:via-gray-950 dark:to-transparent pt-10 pb-0">
             <ChatInput 
                input={input} setInput={setInput} inputImages={inputImages} setInputImages={setInputImages}
                onSend={handleSendMessage} onStop={handleStopGeneration} isLoading={isLoading} isDisabled={activeKeysCount === 0}
                fontSize={settings.fontSize} language={settings.language} activeKeysCount={activeKeysCount} showTokenUsage={settings.showTokenUsage}
                history={messages} historyLimit={settings.historyContextLimit} 
                onGetTokenCount={async (currentInput) => {
                    if (!llmService || apiKeys.length === 0) return 0;
                    const activeKey = apiKeys.find(k => k.isActive);
                    if (!activeKey) return 0;
                    return await llmService.countTokens(activeKey, messages, currentInput, settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n'));
                }} 
                theme={settings.theme}
             />
             <div className="text-center text-[10px] text-gray-400 dark:text-gray-600 pb-0 select-none">
                {t('footer.ai_generated', settings.language)}{APP_VERSION}
             </div>
          </div>
        </main>

        <Suspense fallback={null}>
            <SettingsModal 
                isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} apiKeys={apiKeys} onUpdateKeys={setApiKeys} 
                settings={settings} onUpdateSettings={setSettings} llmService={llmService} onShowToast={addToast}
                onShowDialog={showDialog} knownModels={knownModels} onUpdateKnownModels={setKnownModels}
            />
        </Suspense>
      </div>
    </div>
  );
};

export default App;

export const APP_VERSION = '1.5.3';

export enum Role {
  USER = 'user',
  MODEL = 'model'
}

export interface Message {
  id: string;
  role: Role;
  text: string;
  images?: string[]; // Array of base64 data URIs
  timestamp: number;
  isError?: boolean;
  keyIndex?: number; // 1-based index of the key used
  provider?: ModelProvider; // Track which provider generated this
  model?: string; // The specific model used for this message
  executionTime?: number; // Time taken to generate response in ms
  groupName?: string; // Name of the group the key belonged to
}

export interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
  createdAt: number;
}

export type ModelProvider = 'google' | 'openai' | 'ollama';

export interface KeyGroup {
  id: string;
  name: string;
  isActive?: boolean; // Controls whether the group is enabled during polling
}

export interface KeyConfig {
  id: string;
  key: string;
  provider: ModelProvider; 
  label?: string;
  isActive: boolean;
  usageLimit: number; // Number of requests before switching
  isRateLimited: boolean;
  lastUsed: number;
  baseUrl?: string; // Specific Base URL for this key (OpenAI)
  model?: string;   // Specific Model for this key
  lastErrorCode?: string; // Code of the last error encountered
  groupId?: string; // Optional: ID of the group this key belongs to
}

export enum GeminiModel {
  FLASH = 'gemini-2.5-flash',
  PRO = 'gemini-3-pro-preview',
  FLASH_THINKING = 'gemini-2.5-flash-thinking-preview-01-21',
  IMAGEN = 'imagen-3.0-generate-001'
}

export interface ModelInfo {
  name: string;
  displayName?: string;
  inputTokenLimit?: number;
  outputTokenLimit?: number;
}

export interface SystemPrompt {
  id: string;
  title: string;
  content: string;
  isActive: boolean;
}

export type Theme = 'light' | 'dark' | 'twilight' | 'sky' | 'pink' | 'sunrise' | 'lime' | 'panda' | 'chocolate' | 'vscode-light' | 'vscode-dark';
export type Language = 'en' | 'zh' | 'ja';
export type TextWrappingMode = 'default' | 'forced' | 'auto';
export type AvatarVisibility = 'always' | 'user-only' | 'model-only' | 'never';

export interface SecurityQuestion {
  id: string;
  question: string;
  answer: string;
}

export interface SecurityConfig {
  enabled: boolean;
  password?: string;
  questions: SecurityQuestion[];
  lastLogin: number;
  lockoutDurationSeconds?: number; // New: Duration in seconds for inactivity lockout
}

export interface GenerationConfig {
  temperature: number;
  topP: number;
  topK: number;
  maxOutputTokens: number;
  stream: boolean;
  thinkingBudget?: number; // New: For Gemini 2.5 thinking models
  stripThoughts?: boolean; // New: Strip <think> tags from history to save tokens
}

export interface ScriptConfig {
  inputFilterEnabled: boolean;
  inputFilterCode: string; // The content of the js/ts file
  inputFileName?: string;
  outputFilterEnabled: boolean;
  outputFilterCode: string; // The content of the js/ts file
  outputFileName?: string;
}

export interface AppSettings {
  // Removed global 'model' and 'openAIBaseUrl' as they are now per-key or defaults for new keys
  defaultModel: string; // Default model for new keys
  defaultBaseUrl: string; // Default URL for new OpenAI keys

  systemPrompts: SystemPrompt[];
  theme: Theme;
  language: Language;
  fontSize: number; 
  textWrapping: TextWrappingMode;
  avatarVisibility: AvatarVisibility; // New: Control avatar visibility
  bubbleTransparency: number; // 0-100
  showModelName: boolean; // New: Toggle model name visibility
  showGroupName: boolean; // New: Toggle group name visibility
  kirbyThemeColor: boolean; // New: Toggle kirby icon theme adaptation
  showTokenUsage: boolean; // New: Toggle token usage estimation
  showResponseTimer: boolean; // New: Toggle response execution time display
  smoothAnimation: boolean; // New: Toggle typewriter animation
  historyContextLimit: number; // New: Limit number of past messages sent (0 = unlimited)
  security: SecurityConfig;
  generation: GenerationConfig;
  scripts: ScriptConfig; // New: Script settings

  // API Key Grouping
  enableKeyGrouping?: boolean;
  keyGroups?: KeyGroup[];

  // knownModels removed from AppSettings to separate cache from configuration
  savedModels?: string[]; // Deprecated, kept for interface compat if needed, but logic moved to keys
}

export interface ToastMessage {
  id: string;
  message: string;
  type: 'success' | 'error' | 'info' | 'warning';
}

export interface DialogConfig {
  isOpen: boolean;
  type: 'alert' | 'confirm' | 'input';
  title: string;
  message?: string;
  inputValue?: string;
  inputPlaceholder?: string;
  onConfirm: (value?: string) => void;
  onCancel?: () => void;
}

"use client";

import React, { useEffect } from 'react';
import { CheckCircle, AlertCircle, Info, X, AlertTriangle } from 'lucide-react';
import { ToastMessage } from '../../types';

interface ToastContainerProps {
  toasts: ToastMessage[];
  removeToast: (id: string) => void;
}

const ToastItem: React.FC<{ toast: ToastMessage; onRemove: () => void }> = ({ toast, onRemove }) => {
  useEffect(() => {
    const timer = setTimeout(() => {
      onRemove();
    }, 3000);
    return () => clearTimeout(timer);
  }, [onRemove]);

  const getIcon = () => {
    switch (toast.type) {
      case 'success': return <CheckCircle className="w-5 h-5 text-green-500" />;
      case 'error': return <AlertCircle className="w-5 h-5 text-red-500" />;
      case 'warning': return <AlertTriangle className="w-5 h-5 text-yellow-500" />;
      case 'info': default: return <Info className="w-5 h-5 text-blue-500" />;
    }
  };

  const getStyles = () => {
     switch (toast.type) {
      case 'success': return 'bg-white dark:bg-gray-800 border-green-200 dark:border-green-900/30';
      case 'error': return 'bg-white dark:bg-gray-800 border-red-200 dark:border-red-900/30';
      case 'warning': return 'bg-white dark:bg-gray-800 border-yellow-200 dark:border-yellow-900/30';
      case 'info': default: return 'bg-white dark:bg-gray-800 border-blue-200 dark:border-blue-900/30';
    }
  };

  return (
    <div className={`pointer-events-auto flex items-center gap-3 px-4 py-3 rounded-xl shadow-lg border animate-fade-in-up min-w-[300px] max-w-sm ${getStyles()}`}>
      <div className="flex-shrink-0">{getIcon()}</div>
      <p className="flex-1 text-sm font-medium text-gray-800 dark:text-gray-200">{toast.message}</p>
      <button onClick={onRemove} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300">
        <X className="w-4 h-4" />
      </button>
    </div>
  );
};

export const ToastContainer: React.FC<ToastContainerProps> = ({ toasts, removeToast }) => {
  return (
    <div className="fixed top-4 right-4 z-[100] flex flex-col gap-3 pointer-events-none">
      {toasts.map((toast) => (
        <ToastItem key={toast.id} toast={toast} onRemove={() => removeToast(toast.id)} />
      ))}
    </div>
  );
};

"use client";

import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { LLMService } from './services/llmService';
import { Message, Role, GeminiModel, AppSettings, KeyConfig, ChatSession, ModelProvider, APP_VERSION, ToastMessage, DialogConfig, ModelInfo } from './types';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import { Header } from './components/Header';
import ChatInput from './components/ChatInput';
import { t } from './utils/i18n';
import { ToastContainer } from './components/ui/Toast';
import { CustomDialog } from './components/ui/CustomDialog';
import { executeFilterScript } from './utils/scriptExecutor';

const SettingsModal = lazy(() => import('./components/SettingsModal'));
const SecurityLock = lazy(() => import('./components/SecurityLock'));
const MobileMenu = lazy(() => import('./components/MobileMenu'));

const DEFAULT_MODEL = 'gemini-3-flash-preview';
const STORAGE_KEYS_KEY = 'gemini_omnichat_keys_v4';
const STORAGE_SETTINGS_KEY = 'gemini_omnichat_settings_v8'; 
const STORAGE_SESSIONS_KEY = 'gemini_omnichat_sessions_v1';
const STORAGE_ACTIVE_SESSION_KEY = 'gemini_omnichat_active_session_v1';
const STORAGE_KNOWN_MODELS_KEY = 'gemini_omnichat_known_models_v1';

const ENV_KEY = process.env.API_KEY || '';

const DEFAULT_KNOWN_MODELS: ModelInfo[] = [
    { name: 'gemini-3-flash-preview', inputTokenLimit: 1048576, outputTokenLimit: 8192 },
    { name: 'gemini-3-pro-preview', inputTokenLimit: 2097152, outputTokenLimit: 8192 }
];

const App: React.FC = () => {
  // --- 状态定义 ---
  const [sessions, setSessions] = useState<ChatSession[]>([]); // 会话列表
  const [activeSessionId, setActiveSessionId] = useState<string>(''); // 当前活动会话 ID
  const [messages, setMessages] = useState<Message[]>([]); // 当前会话的消息记录
  const [input, setInput] = useState(''); // 输入框文本
  const [inputImages, setInputImages] = useState<string[]>([]); // 待发送的图片
  const [isLoading, setIsLoading] = useState(false); // 是否正在生成回复
  const [isSummarizing, setIsSummarizing] = useState(false); // 是否正在总结标题
  const [isSettingsOpen, setIsSettingsOpen] = useState(false); // 设置弹窗开关
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false); // 移动端侧边栏开关
  const [isLocked, setIsLocked] = useState(false); // 隐私安全锁状态
  const [apiKeys, setApiKeys] = useState<KeyConfig[]>([]); // API 密钥池
  const [knownModels, setKnownModels] = useState<ModelInfo[]>(DEFAULT_KNOWN_MODELS); // 已知模型缓存

  // --- 应用配置 ---
  const [settings, setSettings] = useState<AppSettings>({
    defaultModel: DEFAULT_MODEL,
    defaultBaseUrl: 'https://api.openai.com/v1',
    systemPrompts: [],
    theme: 'light', 
    language: 'zh', 
    fontSize: 14,
    textWrapping: 'auto', 
    bubbleTransparency: 100, 
    showModelName: true, 
    showGroupName: false,
    kirbyThemeColor: false, 
    showTokenUsage: false, 
    showResponseTimer: false, 
    smoothAnimation: true, 
    avatarVisibility: 'always', 
    historyContextLimit: 0, 
    security: {
        enabled: false,
        questions: [],
        lastLogin: Date.now(),
        lockoutDurationSeconds: 86400 
    },
    generation: {
        temperature: 1.0,
        topP: 0.95,
        topK: 40,
        maxOutputTokens: 8192,
        stream: false, 
        thinkingBudget: 0, 
        stripThoughts: false 
    },
    scripts: {
        inputFilterEnabled: false,
        inputFilterCode: '',
        outputFilterEnabled: false,
        outputFilterCode: ''
    },
    enableKeyGrouping: false,
    keyGroups: []
  });

  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [dialog, setDialog] = useState<DialogConfig>({
      isOpen: false,
      type: 'alert',
      title: '',
      onConfirm: () => {}
  });

  const [llmService, setLlmService] = useState<LLMService | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const isProcessingRef = useRef(false);

  // --- 辅助工具函数 ---
  const addToast = (message: string, type: 'success' | 'error' | 'info' | 'warning' = 'info') => {
      setToasts(prev => [...prev, { id: uuidv4(), message, type }]);
  };

  const removeToast = (id: string) => {
      setToasts(prev => prev.filter(t => t.id !== id));
  };

  const showDialog = (config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => {
      setDialog({
          isOpen: true,
          type: config.type || 'alert',
          title: config.title,
          message: config.message,
          inputValue: config.inputValue,
          inputPlaceholder: config.inputPlaceholder,
          onConfirm: config.onConfirm,
          onCancel: config.onCancel
      });
  };

  const closeDialog = () => {
      setDialog(prev => ({ ...prev, isOpen: false }));
  };

  const safeJsonParse = (str: string | null, fallback: any = null) => {
    if (!str || !str.trim()) return fallback;
    try {
      return JSON.parse(str);
    } catch (e) {
      console.warn("Failed to parse JSON from storage:", e);
      return fallback;
    }
  };

  /**
   * 节点 1: 挂载初始化
   * 从 LocalStorage 加载所有持久化数据，包括密钥、设置和会话历史。
   */
  useEffect(() => {
    const storedKeys = localStorage.getItem(STORAGE_KEYS_KEY);
    const oldKeysV3 = localStorage.getItem('gemini_omnichat_keys_v3');
    const oldSettingsStr = localStorage.getItem('gemini_omnichat_settings_v5');
    const oldSettings = safeJsonParse(oldSettingsStr);
    const globalModel = oldSettings?.model || DEFAULT_MODEL;
    const globalBaseUrl = oldSettings?.openAIBaseUrl || 'https://api.openai.com/v1';

    let initialKeys: KeyConfig[] = [];

    if (storedKeys) {
      initialKeys = safeJsonParse(storedKeys, []);
    } else if (oldKeysV3) {
      const parsed = safeJsonParse(oldKeysV3, []);
      initialKeys = parsed.map((k: any) => ({
          ...k,
          model: globalModel,
          baseUrl: k.provider === 'openai' ? globalBaseUrl : ''
      }));
    } else if (ENV_KEY) {
      initialKeys = ENV_KEY.split(',').map(k => k.trim()).filter(Boolean).map(k => ({
        id: uuidv4(),
        key: k,
        provider: 'google' as ModelProvider,
        isActive: true,
        usageLimit: 5, 
        isRateLimited: false,
        lastUsed: 0,
        model: DEFAULT_MODEL
      }));
    }
    setApiKeys(initialKeys);

    const storedSettings = localStorage.getItem(STORAGE_SETTINGS_KEY);
    let loadedSettings = settings;
    let loadedKnownModels = DEFAULT_KNOWN_MODELS;

    const storedKnownModels = localStorage.getItem(STORAGE_KNOWN_MODELS_KEY);
    if (storedKnownModels) {
        // Merge stored models with defaults to ensure new defaults appear
        const parsedStoredModels = safeJsonParse(storedKnownModels, []);
        // Create a map for easy lookup by name
        const storedModelMap = new Map(parsedStoredModels.map((m: any) => [m.name, m]));

        // Start with defaults
        const mergedModels = [...DEFAULT_KNOWN_MODELS];

        // Add any stored models that are NOT in defaults
        parsedStoredModels.forEach((m: any) => {
            if (!mergedModels.find(dm => dm.name === m.name)) {
                mergedModels.push(m);
            }
        });

        loadedKnownModels = mergedModels;
    }

    if (storedSettings) {
      const parsedSettings = safeJsonParse(storedSettings);
      if (parsedSettings) {
          if (parsedSettings.knownModels && !storedKnownModels) {
              loadedKnownModels = parsedSettings.knownModels;
          }
          if ('knownModels' in parsedSettings) delete parsedSettings.knownModels;
          loadedSettings = { ...settings, ...parsedSettings };
      }
    } 
    setSettings(loadedSettings);
    setKnownModels(loadedKnownModels);

    const effectiveKeys = initialKeys.map(k => {
        if (!k.groupId) return k;
        const group = loadedSettings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    // 初始化核心 LLM 服务
    setLlmService(new LLMService(
        effectiveKeys, 
        {
            onKeyError: (id, errorCode, isFatal = true) => {
                setApiKeys(prev => prev.map(k => {
                    if (k.id !== id) return k;
                    if (isFatal) return { ...k, isActive: false, lastErrorCode: errorCode };
                    else return { ...k, isRateLimited: true, lastUsed: Date.now(), lastErrorCode: errorCode };
                }));
                // Only toast on fatal errors here, LLMService handles other status messages
                if (isFatal) addToast(`${t('error.key_auto_disabled', loadedSettings.language)}${errorCode ? ` (${errorCode})` : ''}`, 'error');
            },
            onStatusMessage: (msg, type) => addToast(msg, type)
        }
    ));

    // 安全锁检查
    if (loadedSettings.security.enabled) {
        const lockoutThresholdMs = (loadedSettings.security.lockoutDurationSeconds || 86400) * 1000;
        if (Date.now() - (loadedSettings.security.lastLogin || 0) > lockoutThresholdMs) setIsLocked(true);
        else setSettings({ ...loadedSettings, security: { ...loadedSettings.security, lastLogin: Date.now() } });
    }

    // 会话恢复
    const storedSessions = localStorage.getItem(STORAGE_SESSIONS_KEY);
    const storedActiveId = localStorage.getItem(STORAGE_ACTIVE_SESSION_KEY);

    if (storedSessions) {
      const parsedSessions = safeJsonParse(storedSessions, []) as ChatSession[];
      if (parsedSessions.length > 0) {
        setSessions(parsedSessions);
        const targetId = (storedActiveId && parsedSessions.find(s => s.id === storedActiveId)) ? storedActiveId : parsedSessions[0].id;
        setActiveSessionId(targetId);
        setMessages(parsedSessions.find(s => s.id === targetId)?.messages || []);
      } else createNewSession();
    } else createNewSession();
  }, []);

  const createNewSession = () => {
    const newId = uuidv4();
    const newSession: ChatSession = {
      id: newId,
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newId);
    setMessages([]);
  };

  /**
   * 节点 2: 数据同步
   * 监听状态变动并同步至服务层或持久化存储。
   */
  useEffect(() => {
    const effectiveKeys = apiKeys.map(k => {
        if (!k.groupId) return k;
        const group = settings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    if (llmService) llmService.updateKeys(effectiveKeys, settings.keyGroups || []);
    localStorage.setItem(STORAGE_KEYS_KEY, JSON.stringify(apiKeys));
  }, [apiKeys, llmService, settings.keyGroups]);

  useEffect(() => {
    localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(settings));
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-chocolate', 'theme-vscode-light', 'theme-vscode-dark');
    root.classList.add(`theme-${settings.theme}`);
    if (['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme)) root.classList.add('dark');
  }, [settings]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KNOWN_MODELS_KEY, JSON.stringify(knownModels));
  }, [knownModels]);

  useEffect(() => {
    if (!activeSessionId) return;
    setSessions(prev => {
      const idx = prev.findIndex(s => s.id === activeSessionId);
      if (idx === -1) return prev;
      const updated = [...prev];
      updated[idx] = { ...updated[idx], messages };
      return updated;
    });
  }, [messages, activeSessionId]);

  useEffect(() => {
    if (sessions.length > 0) localStorage.setItem(STORAGE_SESSIONS_KEY, JSON.stringify(sessions));
  }, [sessions]);

  useEffect(() => {
    if (activeSessionId) localStorage.setItem(STORAGE_ACTIVE_SESSION_KEY, activeSessionId);
  }, [activeSessionId]);

  /**
   * 节点 3: 消息处理逻辑
   * 处理流式响应并将其分片渲染至 UI。
   */
  const triggerBotResponse = async (historyBefore: Message[], userMessage: Message) => {
    if (!llmService) return;
    setIsLoading(true);

    if (abortControllerRef.current) abortControllerRef.current.abort();
    const controller = new AbortController();
    abortControllerRef.current = controller;

    const tempBotId = uuidv4();
    const botMessage: Message = {
      id: tempBotId,
      role: Role.MODEL,
      text: '',
      timestamp: Date.now()
    };

    setMessages([...historyBefore, userMessage, botMessage]);

    const startTime = Date.now();

    try {
      const systemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');
      let historyForApi = historyBefore.filter(m => m.id !== userMessage.id);

      if (settings.generation.stripThoughts) {
        historyForApi = historyForApi.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }

      let contextToSend = historyForApi;
      if (settings.historyContextLimit > 0 && historyForApi.length > settings.historyContextLimit) {
          contextToSend = historyForApi.slice(-settings.historyContextLimit);
      }

      // 执行流式调用
      const { text: fullText, usedKeyIndex, provider, usedModel } = await llmService.streamChatResponse(
        '', 
        contextToSend, 
        userMessage.text, 
        userMessage.images, 
        systemInstruction,
        settings.generation,
        (chunkText) => {
           let processedChunk = chunkText;
           if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
               processedChunk = executeFilterScript(settings.scripts.outputFilterCode, chunkText, { role: 'model', history: [...historyBefore, userMessage] });
           }
           setMessages(prev => prev.map(msg => msg.id === tempBotId ? { ...msg, text: processedChunk } : msg));
        },
        controller.signal,
        settings.language
      );

      const executionTime = Date.now() - startTime;
      let processedFinalText = fullText;

      if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
          processedFinalText = executeFilterScript(settings.scripts.outputFilterCode, fullText, { role: 'model', history: [...historyBefore, userMessage] });
      }

      // Resolve Group Name
      let groupName: string | undefined;
      if (usedKeyIndex && usedKeyIndex > 0 && usedKeyIndex <= apiKeys.length) {
          const usedKey = apiKeys[usedKeyIndex - 1];
          if (usedKey && usedKey.groupId) {
              const group = settings.keyGroups?.find(g => g.id === usedKey.groupId);
              if (group) groupName = group.name;
          }
      }

      setMessages(prev => 
        prev.map(msg => 
          msg.id === tempBotId ? { 
              ...msg, 
              text: processedFinalText, 
              keyIndex: usedKeyIndex, 
              provider: provider, 
              model: usedModel, 
              executionTime: executionTime,
              groupName: groupName
          } : msg
        )
      );
    } catch (error: any) {
      if (error.message !== "Aborted by user") {
         const errorMessage: Message = {
            id: uuidv4(),
            role: Role.MODEL,
            text: `${t('action.error', settings.language)}: ${error.message || t('error.unexpected_error', settings.language)}`,
            timestamp: Date.now(),
            isError: true,
            executionTime: Date.now() - startTime
         };
         setMessages(prev => prev.filter(m => m.id !== tempBotId).concat(errorMessage));
      }
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGeneration = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
          abortControllerRef.current = null;
          setIsLoading(false);
      }
  };

  const handleSendMessage = async () => {
    if (!llmService || isProcessingRef.current) return;
    if (!input.trim() && inputImages.length === 0) return;

    if (apiKeys.filter(k => k.isActive).length === 0) {
      setIsSettingsOpen(true);
      return;
    }

    isProcessingRef.current = true; 

    let processedInput = input.trim();
    if (settings.scripts?.inputFilterEnabled && settings.scripts.inputFilterCode) {
        processedInput = executeFilterScript(settings.scripts.inputFilterCode, processedInput, { role: 'user', history: messages });
    }

    const newMessage: Message = {
      id: uuidv4(),
      role: Role.USER,
      text: processedInput,
      images: inputImages.length > 0 ? [...inputImages] : undefined, 
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newMessage]);
    setInput('');
    setInputImages([]); 

    try {
        await triggerBotResponse(messages, newMessage);
    } finally {
        isProcessingRef.current = false; 
    }
  };

  /**
   * 节点 4: 加载对话功能修复与增强
   * 将对话作为新会话导入，而不是覆盖当前会话，避免用户误操作。
   */
  const handleLoadSession = (loadedMessages: any[], title?: string) => {
      handleStopGeneration();

      // 生成新的会话对象
      const newId = uuidv4();
      const newSession: ChatSession = {
          id: newId,
          title: title || t('msg.new_chat_title', settings.language),
          messages: loadedMessages,
          createdAt: Date.now()
      };

      // 插入到会话列表最前端并立即切换
      setSessions(prev => [newSession, ...prev]);
      setActiveSessionId(newId);
      setMessages(loadedMessages);
      setInput('');

      // 使用更明确的“对话已导入”提示
      addToast(t('success.chat_import', settings.language) || t('msg.config_imported', settings.language), 'success');
  };

  const handleSaveChat = () => {
    const activeSession = sessions.find(s => s.id === activeSessionId);
    const title = activeSession?.title || t('label.session', settings.language);
    const safeTitle = title.replace(/[^a-z0-9\u4e00-\u9fa5]/gi, '_').substring(0, 50);
    const chatData = { title, date: new Date().toISOString(), messages };
    const blob = new Blob([JSON.stringify(chatData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `OmniChat-${safeTitle}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleSelectSession = (sessionId: string) => {
    if (sessionId === activeSessionId) { setIsMobileMenuOpen(false); return; }
    handleStopGeneration();
    const session = sessions.find(s => s.id === sessionId);
    if (session) {
      setActiveSessionId(sessionId);
      setMessages(session.messages);
      setInput('');
      setIsMobileMenuOpen(false);
    }
  };

  const activeKeysCount = apiKeys.filter(k => k.isActive).length;
  const currentSessionTitle = sessions.find(s => s.id === activeSessionId)?.title || t('app.title', settings.language);

  if (isLocked) return (
    <div className={`${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
        <Suspense fallback={<div className="flex h-screen items-center justify-center bg-gray-100 dark:bg-gray-950"></div>}>
            <SecurityLock config={settings.security} onUnlock={() => setIsLocked(false)} lang={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor} />
        </Suspense>
    </div>
  );

  return (
    <div className={`flex h-screen font-sans ${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <CustomDialog config={dialog} onClose={closeDialog} lang={settings.language} />

      <div className="flex w-full h-full bg-transparent text-gray-900 dark:text-gray-100 transition-colors duration-300">
        <Sidebar 
            sessions={sessions} activeSessionId={activeSessionId} activeKeysCount={activeKeysCount} 
            language={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor}
            onNewChat={() => { handleStopGeneration(); createNewSession(); setIsMobileMenuOpen(false); }} 
            onSelectSession={handleSelectSession} 
            onDeleteSession={(e, id) => {
                e.stopPropagation();
                const newSessions = sessions.filter(s => s.id !== id);
                setSessions(newSessions);
                if (activeSessionId === id) {
                   handleStopGeneration();
                   if (newSessions.length > 0) {
                     setActiveSessionId(newSessions[0].id);
                     setMessages(newSessions[0].messages);
                   } else createNewSession();
                }
            }}
            onOpenSettings={() => setIsSettingsOpen(true)}
        />

        <Suspense fallback={null}>
            <MobileMenu 
                isOpen={isMobileMenuOpen} sessions={sessions} activeSessionId={activeSessionId} language={settings.language}
                onClose={() => setIsMobileMenuOpen(false)} onNewChat={() => { handleStopGeneration(); createNewSession(); setIsMobileMenuOpen(false); }} 
                onSelectSession={handleSelectSession}
                onDeleteSession={(e, id) => {
                    e.stopPropagation();
                    const newSessions = sessions.filter(s => s.id !== id);
                    setSessions(newSessions);
                    if (activeSessionId === id) {
                       handleStopGeneration();
                       if (newSessions.length > 0) {
                         setActiveSessionId(newSessions[0].id);
                         setMessages(newSessions[0].messages);
                       } else createNewSession();
                    }
                }} 
                onOpenSettings={() => setIsSettingsOpen(true)}
            />
        </Suspense>

        <main className="flex-1 flex flex-col relative h-full min-w-0 overflow-hidden">
          <Header 
             currentSessionTitle={currentSessionTitle} isSummarizing={isSummarizing} hasMessages={messages.length > 0}
             language={settings.language} onRename={() => {
                const currentSession = sessions.find(s => s.id === activeSessionId);
                showDialog({
                    type: 'input',
                    title: t('msg.rename_chat', settings.language),
                    inputValue: currentSession?.title || '',
                    onConfirm: (newTitle) => {
                        if (newTitle && newTitle.trim()) setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle.trim() } : s));
                    }
                });
             }} 
             onSummarize={async () => {
                if (messages.length === 0 || !llmService) return;
                setIsSummarizing(true); 
                try {
                    const historyText = messages.map(m => `${m.role === Role.USER ? 'User' : 'Model'}: ${m.text}`).join('\n');
                    const prompt = t('msg.summarize_prompt', settings.language) + '\n\n' + historyText;
                    const { text } = await llmService.streamChatResponse('', [], prompt, [], undefined, settings.generation, undefined, undefined, settings.language);
                    const newTitle = text.trim().replace(/['"]/g, '').replace(/\.$/, '').replace(/\*\*/g, ''); 
                    if (newTitle) {
                        setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle } : s));
                        addToast(t('action.ok', settings.language), 'success');
                    }
                } catch (e) {
                    addToast(t('msg.summarize_error', settings.language), 'error');
                } finally { setIsSummarizing(false); }
             }}
             onOpenMobileMenu={() => setIsMobileMenuOpen(true)} 
             onNewChat={() => { handleStopGeneration(); createNewSession(); }} 
             onClearChat={() => {
                if (messages.length === 0) return;
                showDialog({
                    type: 'confirm',
                    title: t('action.clear_chat', settings.language),
                    message: t('msg.confirm_clear_chat', settings.language),
                    onConfirm: () => {
                        handleStopGeneration();
                        setMessages([]);
                        setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, messages: [] } : s));
                    }
                });
             }}
             onOpenSettings={() => setIsSettingsOpen(true)} 
             onSaveChat={handleSaveChat} 
             onLoadSession={handleLoadSession} 
             onShowToast={addToast}
          />

          <ChatInterface 
              messages={messages} isLoading={isLoading} 
              onEditMessage={(id, newText) => setMessages(prev => prev.map(msg => msg.id === id ? { ...msg, text: newText } : msg))} 
              onDeleteMessage={(id) => setMessages(prev => prev.filter(msg => msg.id !== id))} 
              onRegenerate={async (id) => {
                if (!llmService) return;
                const index = messages.findIndex(m => m.id === id);
                if (index === -1) return;
                const targetMsg = messages[index];
                if (targetMsg.role === Role.USER) {
                   await triggerBotResponse(messages.slice(0, index), targetMsg);
                } else {
                  let userMsgIndex = index - 1;
                  while (userMsgIndex >= 0 && messages[userMsgIndex].role !== Role.USER) userMsgIndex--;
                  if (userMsgIndex !== -1) await triggerBotResponse(messages.slice(0, userMsgIndex), messages[userMsgIndex]);
                }
              }} 
              language={settings.language} fontSize={settings.fontSize} 
              textWrapping={settings.textWrapping} bubbleTransparency={settings.bubbleTransparency}
              showModelName={settings.showModelName} showGroupName={settings.showGroupName} showResponseTimer={settings.showResponseTimer} theme={settings.theme}
              kirbyThemeColor={settings.kirbyThemeColor} onShowToast={addToast} smoothAnimation={settings.smoothAnimation}
              avatarVisibility={settings.avatarVisibility}
          />

          <div className="absolute bottom-0 left-0 right-0 z-20 bg-gradient-to-t from-white via-white to-transparent dark:from-gray-950 dark:via-gray-950 dark:to-transparent pt-10 pb-0">
             <ChatInput 
                input={input} setInput={setInput} inputImages={inputImages} setInputImages={setInputImages}
                onSend={handleSendMessage} onStop={handleStopGeneration} isLoading={isLoading} isDisabled={activeKeysCount === 0}
                fontSize={settings.fontSize} language={settings.language} activeKeysCount={activeKeysCount} showTokenUsage={settings.showTokenUsage}
                history={messages} historyLimit={settings.historyContextLimit} 
                onGetTokenCount={async (currentInput) => {
                    if (!llmService || apiKeys.length === 0) return 0;
                    const activeKey = apiKeys.find(k => k.isActive);
                    if (!activeKey) return 0;
                    return await llmService.countTokens(activeKey, messages, currentInput, settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n'));
                }} 
                theme={settings.theme}
             />
             <div className="text-center text-[10px] text-gray-400 dark:text-gray-600 pb-0 select-none">
                {t('footer.ai_generated', settings.language)}{APP_VERSION}
             </div>
          </div>
        </main>

        <Suspense fallback={null}>
            <SettingsModal 
                isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} apiKeys={apiKeys} onUpdateKeys={setApiKeys} 
                settings={settings} onUpdateSettings={setSettings} llmService={llmService} onShowToast={addToast}
                onShowDialog={showDialog} knownModels={knownModels} onUpdateKnownModels={setKnownModels}
            />
        </Suspense>
      </div>
    </div>
  );
};

export default App;
